  if (groundingChunks) {
    groundingChunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
    });
  }

  // Ensure bulletPoints is ALWAYS an array to prevent .map errors
  const slides: Slide[] = (parsed.slides || []).map((s: any, idx: number) => ({
    id: idx,
    title: s.title || "Slide bez názvu",
    bulletPoints: Array.isArray(s.bulletPoints) ? s.bulletPoints : [],
    speakerNotes: s.speakerNotes || "",
    imagePrompt: s.imagePrompt || topic
  }));

  return { slides, sources: sources.slice(0, 4), title: parsed.presentationTitle || topic };
};

export const generateSlideImage = async (imagePrompt: string, retries = 3): Promise<string | undefined> => {
  if (!imagePrompt || imagePrompt.trim() === "") return undefined;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: imagePrompt }] },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return part.inlineData.data;
    }
  } catch (error: any) {
    if (retries > 0) {
        const isQuota = error.message?.includes('429') || error.status === 429;
        const delay = isQuota ? 8000 : 2000;
        await new Promise(resolve => setTimeout(resolve, delay));
        return generateSlideImage(imagePrompt, retries - 1);
    }
    return undefined;
  }
  return undefined;
};

export const generateSlideAudio = async (text: string, voiceName: string = 'Kore', retries = 3): Promise<string | undefined> => {
  if (!text || text.trim() === "") return undefined;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } } },
      },
    });
    const base64PCM = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64PCM) return addWavHeader(base64PCM);
  } catch (error: any) {
    if (retries > 0) {
        await new Promise(resolve => setTimeout(resolve, 5000));
        return generateSlideAudio(text, voiceName, retries - 1);
    }
    return undefined;
  }
  return undefined;
};

export const previewVoice = async (voiceName: string): Promise<string | undefined> => {
    return await generateSlideAudio("Ahoj, tohle je ukázka mého hlasu.", voiceName);
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, LayoutTemplate, BoxSelect, PlayCircle, Speaker, MonitorPlay, Sparkles, ExternalLink } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation } from '../services/htmlExportService';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  if (!text) return null;
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return (
    <span className={className}>
      {parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="font-black text-white bg-blue-500/10 px-1 rounded-sm">{part.slice(2, -2)}</strong>;
        }
        return <span key={i} className="font-medium opacity-90">{part}</span>;
      })}
    </span>
  );
};

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoPlayTimerRef = useRef<number | null>(null);
  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const totalSlides = data?.slides?.length || 0;
  const lastSlide = data?.slides?.[totalSlides - 1];
  const sourceCoords = { x: (lastSlide?.x || 0) + 1600, y: (lastSlide?.y || 0) }; 
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  const decorObjects = useMemo(() => {
      const objects: any[] = [];
      const colors = ['bg-blue-600', 'bg-blue-800', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
      const shapes = ['rounded-full', 'rounded-3xl', 'rounded-xl'];
      const allSlides = [...(data?.slides || []).map(s => ({ x: s.x, y: s.y })), { x: sourceCoords.x, y: sourceCoords.y }];

      allSlides.forEach((slide, idx) => {
          for (let i = 0; i < 6; i++) {
              const seed = idx * 100 + i;
              const size = 60 + seededRandom(seed) * 180;
              const finalX = (slide.x || 0) + (seededRandom(seed + 1) - 0.5) * 2400;
              const finalY = (slide.y || 0) + (seededRandom(seed + 2) - 0.5) * 1800;

              objects.push({
                  id: `decor-${idx}-${i}`,
                  x: finalX,
                  y: finalY,
                  w: size,
                  h: size,
                  colorClass: colors[Math.floor(seededRandom(seed + 6) * colors.length)],
                  shape: shapes[Math.floor(seededRandom(seed + 7) * shapes.length)],
                  style: {
                      animationDuration: `${15 + seededRandom(seed + 3) * 15}s`,
                      animationDelay: `${seededRandom(seed + 4) * -15}s`,
                  },
              });
          }
      });
      return objects;
  }, [data?.slides]);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (audioRef.current) audioRef.current.pause();
    setIsPlaying(false);
    if (autoPlayTimerRef.current) window.clearTimeout(autoPlayTimerRef.current);

    const currentSlide = data?.slides?.[currentIndex];
    if (isAutoPlaying && currentIndex < totalSlides && currentSlide?.audioBase64) {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => {
            setIsPlaying(false);
            autoPlayTimerRef.current = window.setTimeout(nextSlide, 2000);
        };
        audioRef.current.play().then(() => setIsPlaying(true)).catch(e => console.warn("Audio play blocked", e));
    }
  }, [currentIndex, isAutoPlaying]);

  const toggleAudio = () => {
    const currentSlide = data?.slides?.[currentIndex];
    if (currentIndex >= totalSlides || !currentSlide?.audioBase64) return;
    if (audioRef.current && isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
    } else {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => setIsPlaying(false);
        audioRef.current.play();
        setIsPlaying(true);
    }
  };

  const handleManualNavigation = (action: () => void) => {
      setIsAutoPlaying(false);
      if (audioRef.current) audioRef.current.pause();
      action();
  };

  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); else setIsAutoPlaying(false); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleDownloadPPTX = () => generatePPTX({ ...data, presentationTitle: editableTitle });
  const handleDownloadHTML = () => generateHTMLPresentation({ ...data, presentationTitle: editableTitle });

  const currentPos = currentIndex === totalSlides ? sourceCoords : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      <style>{`
        @keyframes float-slow { 
            0%, 100% { transform: translate(0, 0) rotate(0deg); } 
            50% { transform: translate(15px, -20px) rotate(2deg); }
        }
        .animate-float-slow { animation: float-slow 12s ease-in-out infinite; }
      `}</style>

      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none">
        <div className="pointer-events-auto flex gap-3 items-center">
           <button onClick={() => handleManualNavigation(onReset)} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 hover:text-white border border-white/10 shadow-xl"><RefreshCw className="w-5 h-5" /></button>
           <button onClick={() => setIsAutoPlaying(!isAutoPlaying)} className={`flex items-center gap-2 px-5 py-2.5 rounded-full border backdrop-blur-md transition-all font-bold text-sm tracking-wide ${isAutoPlaying ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}>
             {isAutoPlaying ? <div className="w-2.5 h-2.5 bg-white rounded-full animate-pulse" /> : <PlayCircle className="w-5 h-5" />}
             <span>{isAutoPlaying ? 'PREZENTUJI' : 'SPUSTIT'}</span>
           </button>
           <button onClick={toggleAudio} className={`w-11 h-11 flex items-center justify-center rounded-full border backdrop-blur-md transition-all ${isPlaying ? 'bg-blue-500 border-blue-500 text-white shadow-[0_0_20px_rgba(59,130,246,0.4)]' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}><Speaker className="w-5 h-5" /></button>
        </div>

        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-b-2 border-transparent focus:border-blue-500 focus:outline-none w-full truncate tracking-tight transition-all" />
            <div className="flex gap-2">
                <button onClick={handleDownloadHTML} className="bg-slate-900/90 hover:bg-slate-800 text-slate-300 border border-white/10 px-5 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-xl transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> WEB VERZE</button>
                <button onClick={handleDownloadPPTX} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><Download className="w-4 h-4 mr-2" /> PPTX</button>
            </div>
        </div>
      </div>

      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.4s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {decorObjects.map((obj) => (
             <div key={obj.id} className={`absolute ${obj.colorClass} ${obj.shape} animate-float-slow opacity-[0.12] pointer-events-none shadow-[inset_-10px_-10px_20px_rgba(0,0,0,0.3)]`} style={{ left: obj.x, top: obj.y, width: obj.w, height: obj.h, ...obj.style }} />
        ))}

        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            const isReversed = slide.layout === 'reversed';
            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 ease-in-out bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${isReversed ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className="w-1/2 p-14 flex flex-col justify-center">
                            <h3 className={`font-black text-white text-5xl leading-tight mb-8 transition-all duration-700 ${isActive ? 'translate-y-0 opacity-100' : '-translate-y-4 opacity-0'}`}>{slide.title}</h3>
                            <ul className="space-y-6">
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className={`flex items-start transition-all duration-700 delay-[${idx * 100}ms] ${isActive ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-2'}`}>
                                        <span className="w-2.5 h-2.5 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span>
                                        <FormattedText text={bp} className="text-xl text-slate-200 leading-relaxed" />
                                    </li>
                                ))}
                            </ul>
                        </div>
                        <div className="w-1/2 p-8 h-full flex items-center justify-center">
                            <div className={`w-full h-full ${slide.shape || 'rounded-[3rem]'} overflow-hidden relative bg-slate-900 border border-white/10 shadow-2xl`}>
                                {slide.imageBase64 ? <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-700 bg-slate-900/50 animate-pulse"><Sparkles className="w-12 h-12 opacity-20" /></div>}
                                <div className="absolute inset-0 bg-gradient-to-t from-slate-950/40 to-transparent"></div>
                            </div>
                        </div>
                    </div>
                </div>
            );
        })}

        {(data?.sources?.length || 0) > 0 && (
            <div className={`absolute w-[1000px] h-[600px] transition-all duration-1000 bg-[#111827]/90 backdrop-blur-3xl border border-white/5 flex flex-col p-16 shadow-2xl rounded-[3rem] ${totalSlides === currentIndex ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: sourceCoords.x, top: sourceCoords.y }}>
                 <h3 className="text-5xl font-black text-white mb-10 border-b-2 border-white/5 pb-6">Zdroje & Odkazy</h3>
                 <div className="grid grid-cols-2 gap-4">
                    {data.sources.map((source, idx) => (
                        <a key={idx} href={source.uri} target="_blank" className="flex items-center p-6 bg-slate-900/50 border border-white/5 rounded-2xl hover:bg-slate-800 transition-all group">
                            <ExternalLink className="w-6 h-6 text-slate-500 mr-5 group-hover:text-blue-400" />
                            <span className="text-slate-300 font-bold group-hover:text-white truncate text-lg">{source.title}</span>
                        </a>
                    ))}
                 </div>
                 <div className="mt-auto pt-6 text-center"><p className="text-slate-500 text-lg">Vytvořil: <span className="text-blue-500 font-bold">Jiří Jílek</span></p></div>
            </div>
        )}
      </div>

      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onClick={() => handleManualNavigation(prevSlide)} disabled={currentIndex === 0} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronLeft className="w-6 h-6" /></button>
        <div className="text-white font-black text-xl w-20 text-center">{currentIndex + 1}<span className="text-slate-600 text-lg"> / {totalPages}</span></div>
        <button onClick={() => handleManualNavigation(nextSlide)} disabled={currentIndex === totalPages - 1} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronRight className="w-6 h-6" /></button>
      </div>
    </div>
  );
};

import { PresentationData } from "../types";

export const generateHTMLPresentation = (data: PresentationData) => {
  const safeData = JSON.stringify(data).replace(/</g, '\\u003c');
  const title = data?.presentationTitle || data?.topic || "Prezentace";
  const GAP_X = 1600;
  const GAP_Y_OFFSET = 1000;

  const bgObjects = [];
  const colors = ['bg-blue-600', 'bg-indigo-700', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
  const slideCount = data?.slides?.length || 0;
  for (let i = 0; i <= slideCount; i++) {
      for (let j = 0; j < 6; j++) {
          const size = 80 + Math.random() * 200;
          const x = (i * GAP_X) + (Math.random() - 0.5) * 2400;
          const y = (i % 2 === 0 ? 0 : GAP_Y_OFFSET) + (Math.random() - 0.5) * 1800;
          const bg = colors[Math.floor(Math.random() * colors.length)];
          const animDur = 15 + Math.random() * 20;
          bgObjects.push(`<div class="absolute ${bg} rounded-3xl opacity-[0.15] animate-float pointer-events-none" style="left:${x}px; top:${y}px; width:${size}px; height:${size}px; animation-duration:${animDur}s;"></div>`);
      }
  }

  const slidesHtml = (data?.slides || []).map((slide, index) => {
      const x = index % 3 * GAP_X; 
      const y = Math.floor(index / 3) * GAP_Y_OFFSET;

      const isReversed = slide.layout === 'reversed';
      const shapeClass = slide.shape || 'rounded-[3rem]';

      const formatText = (text: string) => {
          if (!text) return "";
          return text.split(/(\*\*.*?\*\*)/g).map(part => {
              if (part.startsWith('**') && part.endsWith('**')) {
                  return `<strong class="font-black text-white">${part.slice(2, -2)}</strong>`;
              }
              return `<span class="font-medium opacity-90">${part}</span>`;
          }).join('');
      };

      const bulletsHtml = (slide.bulletPoints || []).map((bp, idx) => `
          <li class="bullet-point opacity-0 translate-x-[-10px] transition-all duration-700 flex items-start text-slate-200 text-xl" style="transition-delay: ${idx * 100}ms">
              <span class="w-2.5 h-2.5 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500"></span>
              <span class="leading-relaxed">${formatText(bp)}</span>
          </li>`).join('');

      return `
      <div id="slide-${index}" class="slide-card absolute w-[1000px] h-[600px] bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${shapeClass} opacity-40 scale-95 blur-[1px] grayscale-[50%]" style="left: ${x}px; top: ${y}px;" onclick="goToSlide(${index})">
            <div class="flex w-full h-full ${isReversed ? 'flex-row-reverse' : 'flex-row'} relative z-10">
                <div class="w-1/2 p-14 flex flex-col justify-center">
                    <h3 class="text-5xl font-black text-white leading-tight mb-8">${slide.title}</h3>
                    <ul class="space-y-6">${bulletsHtml}</ul>
                </div>
                <div class="w-1/2 p-8 h-full flex items-center justify-center">
                    <div class="w-full h-full ${shapeClass} overflow-hidden bg-slate-900 shadow-2xl border border-white/5 relative">
                        <img src="data:image/png;base64,${slide.imageBase64 || ''}" class="w-full h-full object-cover" />
                        <div class="absolute inset-0 bg-slate-950/20"></div>
                    </div>
                </div>
            </div>
      </div>`;
  }).join('');

  return `
<!DOCTYPE html>
<html lang="cs">
<head>
    <meta charset="UTF-8">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;700;900&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Outfit', sans-serif; background-color: #020617; overflow: hidden; perspective: 2000px; color: white; }
        .slide-card { transition: all 1.0s cubic-bezier(0.2, 0, 0.2, 1); }
        .camera-view { transition: transform 1.4s cubic-bezier(0.2, 0, 0.2, 1); transform-style: preserve-3d; }
        @keyframes float { 0%, 100% { transform: translate(0,0); } 50% { transform: translate(10px,-20px); } }
        .animate-float { animation: float 15s ease-in-out infinite; }
        .slide-active { opacity: 1 !important; transform: scale(1) !important; filter: none !important; blur: 0 !important; z-index: 50 !important; border-color: rgba(255,255,255,0.1) !important; }
        .slide-active .bullet-point { opacity: 1 !important; transform: translateX(0) !important; }
    </style>
</head>
<body>
    <div id="camera" class="absolute top-0 left-0 w-full h-full camera-view">
        ${bgObjects.join('')}
        ${slidesHtml}
    </div>
    <div class="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onclick="prevSlide()" id="btn-prev" class="p-2 text-white disabled:opacity-20"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m15 18-6-6 6-6"/></svg></button>
        <div class="font-black text-xl w-20 text-center"><span id="curr">1</span><span class="text-slate-600 text-lg"> / ${data?.slides?.length || 0}</span></div>
        <button onclick="nextSlide()" id="btn-next" class="p-2 text-white disabled:opacity-20"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m9 18 6-6-6-6"/></svg></button>
    </div>
    <script>
        const data = ${safeData};
        let currentIndex = 0;
        function update() {
            const index = currentIndex;
            const x = index % 3 * 1600;
            const y = Math.floor(index / 3) * 1000;
            const camX = (window.innerWidth/2) - x - 500;
            const camY = (window.innerHeight/2) - y - 300;
            document.getElementById('camera').style.transform = \`translate3d(\${camX}px, \${camY}px, 0)\`;
            for(let i=0; i<(data?.slides?.length || 0); i++) {
                const el = document.getElementById('slide-'+i);
                if(el) {
                  el.className = el.className.replace('slide-active', '').trim();
                  if(i === index) el.classList.add('slide-active');
                }
            }
            document.getElementById('curr').innerText = index + 1;
            document.getElementById('btn-prev').disabled = index === 0;
            document.getElementById('btn-next').disabled = index === (data?.slides?.length || 0) - 1;
        }
        function nextSlide() { if(currentIndex < (data?.slides?.length || 0)-1) { currentIndex++; update(); } }
        function prevSlide() { if(currentIndex > 0) { currentIndex--; update(); } }
        window.addEventListener('keydown', e => { if(e.key==='ArrowRight') nextSlide(); if(e.key==='ArrowLeft') prevSlide(); });
        update();
    </script>
</body>
</html>`;
};

