                  return `<strong class="font-black text-white">${part.slice(2, -2)}</strong>`;
              }
              return `<span class="font-medium opacity-90">${part}</span>`;
          }).join('');
      };

      const bulletCount = slide.bulletPoints?.length || 0;
      const totalChars = (slide.bulletPoints || []).reduce((acc, curr) => acc + curr.length, 0) + slide.title.length;
      let fontSizeClass = 'text-xl';
      if (totalChars > 700) fontSizeClass = 'text-xs';
      else if (totalChars > 500 || bulletCount > 8) fontSizeClass = 'text-sm';
      else if (totalChars > 350 || bulletCount > 6) fontSizeClass = 'text-base';
      else if (totalChars > 200 || bulletCount > 4) fontSizeClass = 'text-lg';

      const bulletsHtml = (slide.bulletPoints || []).map((bp, idx) => `
          <li class="bullet-point opacity-0 translate-x-[-10px] transition-all duration-700 flex items-start text-slate-200 ${fontSizeClass}" style="transition-delay: ${idx * 100}ms">
              <span class="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500"></span>
              <span class="leading-relaxed">${formatText(bp)}</span>
          </li>`).join('');

      return `
      <div id="slide-${index}" class="slide-card absolute w-[1000px] h-[600px] bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${shapeClass} opacity-40 scale-95 blur-[1px] grayscale-[50%]" style="left: ${x}px; top: ${y}px;" onclick="goToSlide(${index})">
            <div class="flex w-full h-full ${hasImage && isReversed ? 'flex-row-reverse' : 'flex-row'} relative z-10">
                <div class="${hasImage ? 'w-1/2 p-14' : 'w-full p-20 text-center'} flex flex-col justify-center">
                    <h3 class="${hasImage ? 'text-5xl mb-8' : 'text-6xl mb-12'} font-black text-white leading-tight">${slide.title}</h3>
                    <ul class="space-y-6 ${!hasImage ? 'max-w-2xl mx-auto text-left' : ''}">${bulletsHtml}</ul>
                </div>
                ${hasImage ? `
                <div class="w-1/2 p-8 h-full flex items-center justify-center transition-all duration-500">
                    <div class="w-full h-full ${shapeClass} overflow-hidden bg-slate-900 shadow-2xl border border-white/5 relative">
                        <img src="data:image/png;base64,${slide.imageBase64}" class="w-full h-full object-cover" />
