            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"></path><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14"></path></svg>
        </button>

        <!-- Notes Button -->
        <button onclick="toggleNotes()" id="btn-notes" class="p-2 text-slate-400 hover:text-white transition-all focus:outline-none" title="Zobrazit poznámky">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg>
        </button>
    </div>

    <script>
        const data = ${safeData};
        let currentIndex = 0;
        let notesVisible = false;
        let audio = new Audio();
        let isPlaying = false;

        function update() {
            const index = currentIndex;
            const slide = data.slides[index];
            if (!slide) return;
            const x = index % 3 * 1600;
            const y = Math.floor(index / 3) * 1000;
            const camX = (window.innerWidth/2) - x - 500;
            const camY = (window.innerHeight/2) - y - 300;

            document.getElementById('camera').style.transform = \`translate3d(\${camX}px, \${camY}px, 0)\`;

            for(let i=0; i<(data?.slides?.length || 0); i++) {
                const el = document.getElementById('slide-'+i);
                if(el) {
                  el.className = el.className.replace('slide-active', '').trim();
                  if(i === index) el.classList.add('slide-active');
                }
            }

            document.getElementById('curr').innerText = index + 1;
            document.getElementById('btn-prev').disabled = index === 0;
            document.getElementById('btn-next').disabled = index === (data?.slides?.length || 0) - 1;

            // Update current notes content from data object directly
            const noteContent = slide.speakerNotes || 'K tomuto slidu nejsou žádné poznámky.';
            document.getElementById('notes-content').textContent = noteContent;

            // Stop audio when moving between slides
            stopAudio();

            // Highlight audio button if audio exists for current slide
            const btnAudio = document.getElementById('btn-audio');
            const btnNotes = document.getElementById('btn-notes');

            if (slide.audioBase64) {
                btnAudio.classList.remove('btn-disabled');
            } else {
                btnAudio.classList.add('btn-disabled');
            }

            if (slide.speakerNotes) {
                btnNotes.classList.remove('btn-disabled');
            } else {
                btnNotes.classList.add('btn-disabled');
            }
        }

        function toggleNotes() {
            notesVisible = !notesVisible;
            const panel = document.getElementById('notes-panel');
            const btn = document.getElementById('btn-notes');
            if(notesVisible) {
                panel.classList.add('visible');
                btn.classList.add('btn-active');
            } else {
                panel.classList.remove('visible');
                btn.classList.remove('btn-active');
            }
        }

        function toggleAudio() {
            const slide = data.slides[currentIndex];
            if (!slide.audioBase64) return;

            if (isPlaying) {
                stopAudio();
            } else {
                audio.src = "data:audio/wav;base64," + slide.audioBase64;
                audio.play();
                isPlaying = true;
                document.getElementById('btn-audio').classList.add('btn-active');
                audio.onended = stopAudio;
            }
        }

        function stopAudio() {
            audio.pause();
            isPlaying = false;
            document.getElementById('btn-audio').classList.remove('btn-active');
        }

        function nextSlide() { if(currentIndex < (data?.slides?.length || 0)-1) { currentIndex++; update(); } }
        function prevSlide() { if(currentIndex > 0) { currentIndex--; update(); } }
        function goToSlide(i) { currentIndex = i; update(); }

        window.addEventListener('keydown', e => { 
            if(e.key==='ArrowRight' || e.key===' ') nextSlide(); 
            if(e.key==='ArrowLeft') prevSlide(); 
            if(e.key==='n' || e.key==='N') toggleNotes();
            if(e.key==='v' || e.key==='V' || e.key==='m' || e.key==='M') toggleAudio();
        });

        update();
    </script>
</body>
</html>`;
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, PlayCircle, Speaker, MonitorPlay, Sparkles, ExternalLink, Wand2, FileText, Send, Loader2, X, Info, Check, HardDrive } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation, ExportOptions } from '../services/htmlExportService';
import { updateSlideContent, generateSlideImage, generateSlideAudio } from '../services/geminiService';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  if (!text) return null;
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return (
    <span className={className}>
      {parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="font-black text-white bg-blue-500/10 px-1 rounded-sm">{part.slice(2, -2)}</strong>;
        }
        return <span key={i} className="font-medium opacity-90">{part}</span>;
      })}
    </span>
  );
};

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const [showNotes, setShowNotes] = useState(false);
  const [aiUpdatePrompt, setAiUpdatePrompt] = useState("");
  const [isUpdatingSlide, setIsUpdatingSlide] = useState(false);
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);

  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    includeAudio: true,
    includeNotes: true,
    includeSources: false
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoPlayTimerRef = useRef<number | null>(null);
  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const totalSlides = data?.slides?.length || 0;
  const lastSlide = data?.slides?.[totalSlides - 1];
  const sourceCoords = { x: (lastSlide?.x || 0) + 1600, y: (lastSlide?.y || 0) }; 
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  const decorObjects = useMemo(() => {
      const objects: any[] = [];
      const colors = ['bg-blue-600', 'bg-blue-800', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
      const shapes = ['rounded-full', 'rounded-3xl', 'rounded-xl'];
      const allSlides = [...(data?.slides || []).map(s => ({ x: s.x, y: s.y })), { x: sourceCoords.x, y: sourceCoords.y }];

      allSlides.forEach((slide, idx) => {
          for (let i = 0; i < 6; i++) {
              const seed = idx * 100 + i;
              const size = 60 + seededRandom(seed) * 180;
              const finalX = (slide.x || 0) + (seededRandom(seed + 1) - 0.5) * 2400;
              const finalY = (slide.y || 0) + (seededRandom(seed + 2) - 0.5) * 1800;

              objects.push({
                  id: `decor-${idx}-${i}`,
                  x: finalX,
                  y: finalY,
                  w: size,
                  h: size,
                  colorClass: colors[Math.floor(seededRandom(seed + 6) * colors.length)],
                  shape: shapes[Math.floor(seededRandom(seed + 7) * shapes.length)],
                  style: {
                      animationDuration: `${15 + seededRandom(seed + 3) * 15}s`,
                      animationDelay: `${seededRandom(seed + 4) * -15}s`,
                  },
              });
          }
      });
      return objects;
  }, [data?.slides]);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (audioRef.current) audioRef.current.pause();
    setIsPlaying(false);
    if (autoPlayTimerRef.current) window.clearTimeout(autoPlayTimerRef.current);

    const currentSlide = data?.slides?.[currentIndex];
    if (isAutoPlaying && currentIndex < totalSlides && currentSlide?.audioBase64) {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => {
            setIsPlaying(false);
            autoPlayTimerRef.current = window.setTimeout(nextSlide, 2000);
        };
        audioRef.current.play().then(() => setIsPlaying(true)).catch(e => console.warn("Audio play blocked", e));
    }
  }, [currentIndex, isAutoPlaying]);

  const toggleAudio = () => {
    const currentSlide = data?.slides?.[currentIndex];
    if (currentIndex >= totalSlides || !currentSlide?.audioBase64) return;
    if (audioRef.current && isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
    } else {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => setIsPlaying(false);
        audioRef.current.play();
        setIsPlaying(true);
    }
  };

  const handleManualNavigation = (action: () => void) => {
      setIsAutoPlaying(false);
      if (audioRef.current) audioRef.current.pause();
      action();
  };

  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); else setIsAutoPlaying(false); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleAiUpdate = async () => {
      const slide = data.slides[currentIndex];
      if (!slide || !aiUpdatePrompt.trim()) return;

      setIsUpdatingSlide(true);
      try {
          const updates = await updateSlideContent(slide, aiUpdatePrompt);
          onUpdateSlide(currentIndex, updates);

          if (updates.imagePrompt) {
              const newImg = await generateSlideImage(updates.imagePrompt);
              if (newImg) onUpdateSlide(currentIndex, { imageBase64: newImg });
          }

          if (updates.speakerNotes) {
              const newAudio = await generateSlideAudio(updates.speakerNotes);
              if (newAudio) onUpdateSlide(currentIndex, { audioBase64: newAudio });
          }

          setAiUpdatePrompt("");
      } catch (e) {
          console.error("AI update failed", e);
      } finally {
          setIsUpdatingSlide(false);
      }
  };

  const handleDownloadPPTX = () => generatePPTX({ ...data, presentationTitle: editableTitle });

  const handleDownloadHTML = () => {
    const html = generateHTMLPresentation({ ...data, presentationTitle: editableTitle }, exportOptions);
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${editableTitle.replace(/[^a-z0-9]/gi, '_')}_Prezentace.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setIsExportDialogOpen(false);
  };

  const estimatedSize = useMemo(() => {
    let size = 25000; // Base HTML + Scripts overhead
    data.slides.forEach(s => {
        if (s.imageBase64) size += s.imageBase64.length;
        if (exportOptions.includeAudio && s.audioBase64) size += s.audioBase64.length;
        if (exportOptions.includeNotes && s.speakerNotes) size += s.speakerNotes.length * 2;
    });
    if (exportOptions.includeSources) size += JSON.stringify(data.sources).length;
    return (size / (1024 * 1024)).toFixed(2);
  }, [data, exportOptions]);

  const currentPos = currentIndex === totalSlides ? sourceCoords : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  const currentSlide = data?.slides?.[currentIndex];

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      <style>{`
        @keyframes float-slow { 
            0%, 100% { transform: translate(0, 0) rotate(0deg); } 
            50% { transform: translate(15px, -20px) rotate(2deg); }
        }
        .animate-float-slow { animation: float-slow 12s ease-in-out infinite; }
      `}</style>

      {/* Header Controls */}
      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none">
        <div className="pointer-events-auto flex gap-3 items-center">
           <button onClick={() => handleManualNavigation(onReset)} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 hover:text-white border border-white/10 shadow-xl" title="Nová prezentace"><RefreshCw className="w-5 h-5" /></button>
           <button onClick={() => setIsAutoPlaying(!isAutoPlaying)} className={`flex items-center gap-2 px-5 py-2.5 rounded-full border backdrop-blur-md transition-all font-bold text-sm tracking-wide ${isAutoPlaying ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}>
             {isAutoPlaying ? <div className="w-2.5 h-2.5 bg-white rounded-full animate-pulse" /> : <PlayCircle className="w-5 h-5" />}
             <span>{isAutoPlaying ? 'PREZENTUJI' : 'SPUSTIT'}</span>
           </button>
           <button onClick={toggleAudio} className={`w-11 h-11 flex items-center justify-center rounded-full border backdrop-blur-md transition-all ${isPlaying ? 'bg-blue-500 border-blue-500 text-white shadow-[0_0_20px_rgba(59,130,246,0.4)]' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}><Speaker className="w-5 h-5" /></button>
           <button onClick={() => setShowNotes(!showNotes)} className={`w-11 h-11 flex items-center justify-center rounded-full border backdrop-blur-md transition-all ${showNotes ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`} title="Poznámky řečníka"><FileText className="w-5 h-5" /></button>
        </div>

        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-b-2 border-transparent focus:border-blue-500 focus:outline-none w-full truncate tracking-tight transition-all" />
            <div className="flex gap-2">
                <button onClick={() => setIsExportDialogOpen(true)} className="bg-slate-900/90 hover:bg-slate-800 text-slate-300 border border-white/10 px-5 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-xl transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> WEB VERZE</button>
                <button onClick={handleDownloadPPTX} className="bg-blue-600 hover:bg-blue-500 text-white px-5 py-2.5 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><Download className="w-4 h-4 mr-2" /> PPTX</button>
            </div>
        </div>
      </div>

      {/* Main Canvas Viewport */}
      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.4s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {decorObjects.map((obj) => (
             <div key={obj.id} className={`absolute ${obj.colorClass} ${obj.shape} animate-float-slow opacity-[0.12] pointer-events-none shadow-[inset_-10px_-10px_20px_rgba(0,0,0,0.3)]`} style={{ left: obj.x, top: obj.y, width: obj.w, height: obj.h, ...obj.style }} />
        ))}

        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            const isReversed = slide.layout === 'reversed';
            const hasImage = !!slide.imageBase64;

            const bulletCount = slide.bulletPoints?.length || 0;
            const totalChars = (slide.bulletPoints || []).reduce((acc, curr) => acc + curr.length, 0) + slide.title.length;

            let fontSizeClass = 'text-xl';
            if (totalChars > 700) fontSizeClass = 'text-xs';
            else if (totalChars > 500 || bulletCount > 8) fontSizeClass = 'text-sm';
            else if (totalChars > 350 || bulletCount > 6) fontSizeClass = 'text-base';
            else if (totalChars > 200 || bulletCount > 4) fontSizeClass = 'text-lg';

            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 ease-in-out bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${isReversed && hasImage ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`${hasImage ? 'w-1/2 p-12' : 'w-full p-20 text-center'} flex flex-col justify-center transition-all duration-700`}>
                            <h3 className={`font-black text-white ${hasImage ? 'text-5xl' : 'text-6xl mb-12'} leading-tight mb-8 transition-all duration-700 ${isActive ? 'translate-y-0 opacity-100' : '-translate-y-4 opacity-0'}`}>{slide.title}</h3>
                            <ul className={`space-y-4 ${!hasImage ? 'max-w-3xl mx-auto text-left' : ''}`}>
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className={`flex items-start transition-all duration-700 delay-[${idx * 100}ms] ${isActive ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-2'}`}>
                                        <span className="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span>
                                        <FormattedText text={bp} className={`${fontSizeClass} text-slate-200 leading-relaxed`} />
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {hasImage && (
                            <div className="w-1/2 p-8 h-full flex items-center justify-center">
                                <div className={`w-full h-full ${slide.shape || 'rounded-[3rem]'} overflow-hidden relative bg-slate-900 border border-white/10 shadow-2xl`}>
                                    <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover" alt={slide.title} />
                                    <div className="absolute inset-0 bg-gradient-to-t from-slate-950/40 to-transparent"></div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            );
        })}

        {(data?.sources?.length || 0) > 0 && (
            <div className={`absolute w-[1000px] h-[600px] transition-all duration-1000 bg-[#111827]/90 backdrop-blur-3xl border border-white/5 flex flex-col p-16 shadow-2xl rounded-[3rem] ${totalSlides === currentIndex ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: sourceCoords.x, top: sourceCoords.y }}>
                 <h3 className="text-5xl font-black text-white mb-10 border-b-2 border-white/5 pb-6">Zdroje & Odkazy</h3>
                 <div className="grid grid-cols-2 gap-4">
                    {data.sources.map((source, idx) => (
                        <a key={idx} href={source.uri} target="_blank" rel="noopener noreferrer" className="flex items-center p-6 bg-slate-900/50 border border-white/5 rounded-2xl hover:bg-slate-800 transition-all group">
                            <ExternalLink className="w-6 h-6 text-slate-500 mr-5 group-hover:text-blue-400" />
                            <span className="text-slate-300 font-bold group-hover:text-white truncate text-lg">{source.title}</span>
                        </a>
                    ))}
                 </div>
                 <div className="mt-auto pt-6 text-center"><p className="text-slate-500 text-lg">Vytvořil: <span className="text-blue-500 font-bold">Jiří Jílek</span></p></div>
            </div>
        )}
      </div>

      {/* Export Dialog */}
      {isExportDialogOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/60 backdrop-blur-sm animate-fade-in">
              <div className="w-full max-w-md bg-slate-900/90 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-in">
                  <div className="p-8 border-b border-white/5 flex justify-between items-center">
                      <div>
                          <h3 className="text-2xl font-black text-white tracking-tight flex items-center">
                            <MonitorPlay className="w-6 h-6 mr-3 text-blue-500" /> Exportovat Web
                          </h3>
                          <p className="text-slate-400 text-sm mt-1">Nastav si úsporný export své stránky.</p>
                      </div>
                      <button onClick={() => setIsExportDialogOpen(false)} className="p-2 rounded-full hover:bg-white/5 transition-colors">
                          <X className="w-6 h-6 text-slate-500" />
                      </button>
                  </div>

                  <div className="p-8 space-y-6">
                      <div className="flex items-center justify-between group">
                          <div className="flex items-center gap-4">
                              <div className={`p-3 rounded-2xl transition-all ${exportOptions.includeAudio ? 'bg-blue-500/10 text-blue-400' : 'bg-slate-800 text-slate-600'}`}>
                                  <Speaker className="w-5 h-5" />
                              </div>
                              <div>
                                  <span className="block font-bold text-slate-200">Audio Vyprávění</span>
                                  <span className="text-xs text-slate-500">Zabírá nejvíce místa (Base64)</span>
                              </div>
                          </div>
                          <button 
                            onClick={() => setExportOptions(prev => ({ ...prev, includeAudio: !prev.includeAudio }))}
                            className={`w-14 h-8 rounded-full relative transition-all duration-300 ${exportOptions.includeAudio ? 'bg-blue-600' : 'bg-slate-800'}`}
                          >
                              <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-all duration-300 ${exportOptions.includeAudio ? 'translate-x-6' : 'translate-x-0 shadow-lg'}`} />
                          </button>
                      </div>

                      <div className="flex items-center justify-between group">
                          <div className="flex items-center gap-4">
                              <div className={`p-3 rounded-2xl transition-all ${exportOptions.includeNotes ? 'bg-indigo-500/10 text-indigo-400' : 'bg-slate-800 text-slate-600'}`}>
                                  <FileText className="w-5 h-5" />
                              </div>
                              <div>
                                  <span className="block font-bold text-slate-200">Poznámky & Tipy</span>
                                  <span className="text-xs text-slate-500">Užitečné pro presentování</span>
                              </div>
                          </div>
                          <button 
                            onClick={() => setExportOptions(prev => ({ ...prev, includeNotes: !prev.includeNotes }))}
                            className={`w-14 h-8 rounded-full relative transition-all duration-300 ${exportOptions.includeNotes ? 'bg-indigo-600' : 'bg-slate-800'}`}
                          >
                              <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-all duration-300 ${exportOptions.includeNotes ? 'translate-x-6' : 'translate-x-0 shadow-lg'}`} />
                          </button>
                      </div>

                      <div className="flex items-center justify-between group">
                          <div className="flex items-center gap-4">
                              <div className={`p-3 rounded-2xl transition-all ${exportOptions.includeSources ? 'bg-slate-700 text-slate-300' : 'bg-slate-800 text-slate-600'}`}>
                                  <ExternalLink className="w-5 h-5" />
                              </div>
                              <div>
                                  <span className="block font-bold text-slate-200">Stránka se Zdroji</span>
                                  <span className="text-xs text-slate-500">Seznam odkazů na konci</span>
                              </div>
                          </div>
                          <button 
                            onClick={() => setExportOptions(prev => ({ ...prev, includeSources: !prev.includeSources }))}
                            className={`w-14 h-8 rounded-full relative transition-all duration-300 ${exportOptions.includeSources ? 'bg-slate-600' : 'bg-slate-800'}`}
                          >
                              <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-all duration-300 ${exportOptions.includeSources ? 'translate-x-6' : 'translate-x-0 shadow-lg'}`} />
                          </button>
                      </div>

                      <div className="pt-4 mt-6 border-t border-white/5 flex items-center justify-between">
                          <div className="flex items-center text-slate-400 gap-2">
                              <HardDrive className="w-4 h-4" />
                              <span className="text-xs font-bold tracking-widest uppercase">Odhadovaná Velikost</span>
                          </div>
                          <span className={`text-sm font-black font-mono px-3 py-1 rounded-lg ${parseFloat(estimatedSize) > 5 ? 'text-amber-400 bg-amber-400/10' : 'text-emerald-400 bg-emerald-400/10'}`}>
                              {estimatedSize} MB
                          </span>
                      </div>
                  </div>

                  <div className="p-8 pt-0 flex gap-3">
                      <button onClick={() => setIsExportDialogOpen(false)} className="flex-1 py-4 rounded-2xl font-bold text-slate-400 hover:text-white hover:bg-white/5 transition-all">Zrušit</button>
                      <button onClick={handleDownloadHTML} className="flex-[2] py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black shadow-xl shadow-blue-900/40 transition-all flex items-center justify-center gap-2">
                          STÁHNOUT SOUBOR <Download className="w-5 h-5" />
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Speaker Notes Drawer */}
      <div className={`fixed bottom-24 right-8 w-80 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl z-[60] transition-all duration-500 transform ${showNotes ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0 pointer-events-none'}`}>
          <div className="p-5 border-b border-white/5 flex justify-between items-center">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center"><FileText className="w-3.5 h-3.5 mr-2 text-indigo-400" /> Poznámky k prezentaci</h4>
              <button onClick={() => setShowNotes(false)} className="text-slate-600 hover:text-white transition-colors text-xs font-bold uppercase">Zavřít</button>
          </div>
          <div className="p-5 max-h-[300px] overflow-y-auto">
              <textarea 
                className="w-full bg-transparent text-slate-300 text-sm leading-relaxed focus:outline-none resize-none min-h-[150px] font-medium"
                value={currentSlide?.speakerNotes || ""}
                onChange={(e) => onUpdateSlide(currentIndex, { speakerNotes: e.target.value })}
                placeholder="Sem můžeš napsat své poznámky k tomuto slidu..."
              />
          </div>
      </div>

      {/* Footer Navigation & AI Bar */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-4 z-50 w-full max-w-xl">
        {currentIndex < totalSlides && (
            <div className={`w-full bg-slate-900/90 backdrop-blur-xl border border-white/10 rounded-full px-6 py-2.5 flex items-center shadow-2xl transition-all ${isUpdatingSlide ? 'opacity-50' : 'opacity-100'}`}>
                <Wand2 className="w-4 h-4 text-blue-400 mr-4 flex-shrink-0" />
                <input 
                    type="text" 
                    value={aiUpdatePrompt}
                    onChange={(e) => setAiUpdatePrompt(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleAiUpdate()}
                    placeholder="Chceš tenhle slide upravit? Napiš co..."
                    className="bg-transparent border-none focus:outline-none text-slate-300 text-sm w-full font-medium"
                    disabled={isUpdatingSlide}
                />
                <button 
                    onClick={handleAiUpdate}
                    disabled={isUpdatingSlide || !aiUpdatePrompt.trim()}
                    className="ml-3 p-1.5 bg-blue-600 rounded-full text-white hover:bg-blue-500 transition-all disabled:opacity-20 disabled:grayscale"
                >
                    {isUpdatingSlide ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                </button>
            </div>
        )}

        <div className="flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl">
            <button onClick={() => handleManualNavigation(prevSlide)} disabled={currentIndex === 0} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all focus:outline-none"><ChevronLeft className="w-6 h-6" /></button>
            <div className="text-white font-black text-xl w-20 text-center">{currentIndex + 1}<span className="text-slate-600 text-lg"> / {totalPages}</span></div>
            <button onClick={() => handleManualNavigation(nextSlide)} disabled={currentIndex === totalPages - 1} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all focus:outline-none"><ChevronRight className="w-6 h-6" /></button>
        </div>
      </div>
    </div>
  );
};

import { PresentationData } from "../types";

export interface ExportOptions {
  includeAudio: boolean;
  includeNotes: boolean;
  includeSources: boolean;
  includeAnimations: boolean;
  includeDecorations: boolean;
  format: 'html' | 'aspx';
}

export const generateHTMLPresentation = (data: PresentationData, options: ExportOptions) => {
  const filteredData = {
    ...data,
    slides: data.slides.map(s => ({
      ...s,
      audioBase64: options.includeAudio ? s.audioBase64 : undefined,
      speakerNotes: options.includeNotes ? s.speakerNotes : undefined
    })),
    sources: options.includeSources ? data.sources : []
  };

  const safeData = JSON.stringify(filteredData).replace(/</g, '\\u003c');
  const title = data?.presentationTitle || data?.topic || "Prezentace";
  const GAP_X = 1600;
  const GAP_Y_OFFSET = 1000;

  const bgObjects = [];
  if (options.includeDecorations) {
    const colors = ['bg-blue-600', 'bg-indigo-700', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
    const slideCount = data?.slides?.length || 0;
    for (let i = 0; i <= slideCount; i++) {
        for (let j = 0; j < 4; j++) {
            const size = 80 + Math.random() * 200;
            const x = (i * GAP_X) + (Math.random() - 0.5) * 2400;
            const y = (i % 2 === 0 ? 0 : GAP_Y_OFFSET) + (Math.random() - 0.5) * 1800;
            const bg = colors[Math.floor(Math.random() * colors.length)];
            const animDur = 15 + Math.random() * 20;
            bgObjects.push(`<div class="absolute ${bg} rounded-3xl opacity-[0.12] ${options.includeAnimations ? 'animate-float' : ''} pointer-events-none" style="left:${x}px; top:${y}px; width:${size}px; height:${size}px; animation-duration:${animDur}s;"></div>`);
        }
    }
  }

  const slidesHtml = (data?.slides || []).map((slide, index) => {
      const x = index % 3 * GAP_X; 
      const y = Math.floor(index / 3) * GAP_Y_OFFSET;

      const hasImage = !!slide.imageBase64;
      const isReversed = slide.layout === 'reversed';
      const shapeClass = slide.shape || 'rounded-[3rem]';

      const formatText = (text: string) => {
          if (!text) return "";
          return text.split(/(\*\*.*?\*\*)/g).map(part => {
              if (part.startsWith('**') && part.endsWith('**')) {
                  return `<strong class="font-black text-white">${part.slice(2, -2)}</strong>`;
              }
              return `<span class="font-medium opacity-90">${part}</span>`;
          }).join('');
      };

      const bulletCount = slide.bulletPoints?.length || 0;
      const totalChars = (slide.bulletPoints || []).reduce((acc, curr) => acc + curr.length, 0) + slide.title.length;
      let fontSizeClass = 'text-xl';
      if (totalChars > 700) fontSizeClass = 'text-xs';
      else if (totalChars > 500 || bulletCount > 8) fontSizeClass = 'text-sm';
      else if (totalChars > 350 || bulletCount > 6) fontSizeClass = 'text-base';
      else if (totalChars > 200 || bulletCount > 4) fontSizeClass = 'text-lg';

      const bulletsHtml = (slide.bulletPoints || []).map((bp, idx) => `
          <li class="bullet-point ${options.includeAnimations ? 'opacity-0 translate-x-[-10px]' : 'opacity-100'} transition-all duration-700 flex items-start text-slate-200 ${fontSizeClass}" style="transition-delay: ${idx * 100}ms">
              <span class="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500"></span>
              <span class="leading-relaxed">${formatText(bp)}</span>
          </li>`).join('');

      return `
      <div id="slide-${index}" class="slide-card absolute w-[1000px] h-[600px] bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${shapeClass} opacity-40 scale-95 blur-[1px] grayscale-[50%]" style="left: ${x}px; top: ${y}px;" onclick="goToSlide(${index})">
            <div class="flex w-full h-full ${hasImage && isReversed ? 'flex-row-reverse' : 'flex-row'} relative z-10">
                <div class="${hasImage ? 'w-1/2 p-14' : 'w-full p-20 text-center'} flex flex-col justify-center">
                    <h3 class="${hasImage ? 'text-5xl mb-8' : 'text-6xl mb-12'} font-black text-white leading-tight">${slide.title}</h3>
                    <ul class="space-y-6 ${!hasImage ? 'max-w-2xl mx-auto text-left' : ''}">${bulletsHtml}</ul>
                </div>
                ${hasImage ? `
                <div class="w-1/2 p-8 h-full flex items-center justify-center transition-all duration-500">
                    <div class="w-full h-full ${shapeClass} overflow-hidden bg-slate-900 shadow-2xl border border-white/5 relative">
                        <img src="data:image/png;base64,${slide.imageBase64}" class="w-full h-full object-cover" />
                        <div class="absolute inset-0 bg-slate-950/20"></div>
                    </div>
                </div>` : ''}
            </div>
      </div>`;
  }).join('');

  return `
<!DOCTYPE html>
<html lang="cs">
<head>
    <meta charset="UTF-8">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;700;900&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Outfit', sans-serif; background-color: #020617; overflow: hidden; perspective: 2000px; color: white; }
        .slide-card { transition: all ${options.includeAnimations ? '1.0s' : '0.1s'} cubic-bezier(0.2, 0, 0.2, 1); }
        .camera-view { transition: transform ${options.includeAnimations ? '1.4s' : '0.1s'} cubic-bezier(0.2, 0, 0.2, 1); transform-style: preserve-3d; }
        @keyframes float { 0%, 100% { transform: translate(0,0); } 50% { transform: translate(10px,-20px); } }
        .animate-float { animation: float 15s ease-in-out infinite; }
        .slide-active { opacity: 1 !important; transform: scale(1) !important; filter: none !important; blur: 0 !important; z-index: 50 !important; border-color: rgba(255,255,255,0.1) !important; }
        .slide-active .bullet-point { opacity: 1 !important; transform: translateX(0) !important; }
        #notes-panel { transition: transform 0.4s ease, opacity 0.4s ease; transform: translateY(20px); opacity: 0; pointer-events: none; }
        #notes-panel.visible { transform: translateY(0); opacity: 1; pointer-events: auto; }
        .btn-active { color: #818cf8 !important; }
        .btn-disabled { opacity: 0.2 !important; pointer-events: none !important; }
    </style>
</head>
<body>
    <div id="camera" class="absolute top-0 left-0 w-full h-full camera-view">
        ${bgObjects.join('')}
        ${slidesHtml}
    </div>

    <div id="notes-panel" class="fixed bottom-24 right-8 w-96 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl z-[100] p-6">
        <h4 class="text-xs font-black uppercase tracking-widest text-slate-400 mb-4 flex items-center">
            <svg class="w-4 h-4 mr-2 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" stroke-width="2"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
            POZNÁMKY K PREZENTACI & TIPY
        </h4>
        <div id="notes-content" class="text-slate-300 text-sm leading-relaxed font-medium max-h-64 overflow-y-auto pr-3 whitespace-pre-wrap"></div>
    </div>

    <div class="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onclick="prevSlide()" id="btn-prev" class="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all focus:outline-none"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m15 18-6-6 6-6"/></svg></button>
        <div class="font-black text-xl w-20 text-center flex items-center justify-center">
            <span id="curr">1</span><span class="text-slate-600 text-lg"> / ${data?.slides?.length || 0}</span>
        </div>
        <button onclick="nextSlide()" id="btn-next" class="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all focus:outline-none"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m9 18 6-6-6-6"/></svg></button>
        <div class="w-px h-6 bg-white/10 mx-2"></div>
        <button onclick="toggleAudio()" id="btn-audio" class="p-2 text-slate-400 hover:text-white transition-all focus:outline-none" title="Přehrát komentář">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"></path><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14"></path></svg>
        </button>
        <button onclick="toggleNotes()" id="btn-notes" class="p-2 text-slate-400 hover:text-white transition-all focus:outline-none" title="Zobrazit poznámky">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg>
        </button>
    </div>

    <script>
        const data = ${safeData};
        let currentIndex = 0;
        let notesVisible = false;
        let audio = new Audio();
        let isPlaying = false;

        function update() {
            const index = currentIndex;
            const slide = data.slides[index];
            if (!slide) return;
            const x = index % 3 * 1600;
            const y = Math.floor(index / 3) * 1000;
            const camX = (window.innerWidth/2) - x - 500;
            const camY = (window.innerHeight/2) - y - 300;

            document.getElementById('camera').style.transform = \`translate3d(\${camX}px, \${camY}px, 0)\`;

            for(let i=0; i<(data?.slides?.length || 0); i++) {
                const el = document.getElementById('slide-'+i);
                if(el) {
                  el.className = el.className.replace('slide-active', '').trim();
                  if(i === index) el.classList.add('slide-active');
                }
            }

            document.getElementById('curr').innerText = index + 1;
            document.getElementById('btn-prev').disabled = index === 0;
            document.getElementById('btn-next').disabled = index === (data?.slides?.length || 0) - 1;

            const noteContent = slide.speakerNotes || 'K tomuto slidu nejsou žádné poznámky.';
            document.getElementById('notes-content').textContent = noteContent;
            stopAudio();

            const btnAudio = document.getElementById('btn-audio');
            const btnNotes = document.getElementById('btn-notes');
            if (slide.audioBase64) btnAudio.classList.remove('btn-disabled'); else btnAudio.classList.add('btn-disabled');
            if (slide.speakerNotes) btnNotes.classList.remove('btn-disabled'); else btnNotes.classList.add('btn-disabled');
        }

        function toggleNotes() {
            notesVisible = !notesVisible;
            const panel = document.getElementById('notes-panel');
            const btn = document.getElementById('btn-notes');
            if(notesVisible) { panel.classList.add('visible'); btn.classList.add('btn-active'); }
            else { panel.classList.remove('visible'); btn.classList.remove('btn-active'); }
        }

        function toggleAudio() {
            const slide = data.slides[currentIndex];
            if (!slide.audioBase64) return;
            if (isPlaying) { stopAudio(); } 
            else {
                audio.src = "data:audio/wav;base64," + slide.audioBase64;
                audio.play();
                isPlaying = true;
                document.getElementById('btn-audio').classList.add('btn-active');
                audio.onended = stopAudio;
            }
        }

        function stopAudio() {
            audio.pause();
            isPlaying = false;
            document.getElementById('btn-audio').classList.remove('btn-active');
        }

        function nextSlide() { if(currentIndex < (data?.slides?.length || 0)-1) { currentIndex++; update(); } }
        function prevSlide() { if(currentIndex > 0) { currentIndex--; update(); } }
        function goToSlide(i) { currentIndex = i; update(); }

        window.addEventListener('keydown', e => { 
            if(e.key==='ArrowRight' || e.key===' ') nextSlide(); 
            if(e.key==='ArrowLeft') prevSlide(); 
            if(e.key==='n' || e.key==='N') toggleNotes();
            if(e.key==='v' || e.key==='V' || e.key==='m' || e.key==='M') toggleAudio();
        });

        update();
    </script>
</body>
</html>`;
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, PlayCircle, Speaker, MonitorPlay, Sparkles, ExternalLink, Wand2, FileText, Send, Loader2, X, Info, Check, HardDrive, Zap, Layout } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation, ExportOptions } from '../services/htmlExportService';
import { updateSlideContent, generateSlideImage, generateSlideAudio } from '../services/geminiService';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  if (!text) return null;
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return (
    <span className={className}>
      {parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="font-black text-white bg-blue-500/10 px-1 rounded-sm">{part.slice(2, -2)}</strong>;
        }
        return <span key={i} className="font-medium opacity-90">{part}</span>;
      })}
    </span>
  );
};

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const [showNotes, setShowNotes] = useState(false);
  const [aiUpdatePrompt, setAiUpdatePrompt] = useState("");
  const [isUpdatingSlide, setIsUpdatingSlide] = useState(false);
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);

  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    includeAudio: true,
    includeNotes: true,
    includeSources: true,
    includeAnimations: true,
    includeDecorations: true,
    format: 'html'
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoPlayTimerRef = useRef<number | null>(null);
  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const totalSlides = data?.slides?.length || 0;
  const lastSlide = data?.slides?.[totalSlides - 1];
  const sourceCoords = { x: (lastSlide?.x || 0) + 1600, y: (lastSlide?.y || 0) }; 
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  const decorObjects = useMemo(() => {
      const objects: any[] = [];
      const colors = ['bg-blue-600', 'bg-blue-800', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
      const shapes = ['rounded-full', 'rounded-3xl', 'rounded-xl'];
      const allSlides = [...(data?.slides || []).map(s => ({ x: s.x, y: s.y })), { x: sourceCoords.x, y: sourceCoords.y }];

      allSlides.forEach((slide, idx) => {
          for (let i = 0; i < 6; i++) {
              const seed = idx * 100 + i;
              const size = 60 + seededRandom(seed) * 180;
              const finalX = (slide.x || 0) + (seededRandom(seed + 1) - 0.5) * 2400;
              const finalY = (slide.y || 0) + (seededRandom(seed + 2) - 0.5) * 1800;

              objects.push({
                  id: `decor-${idx}-${i}`,
                  x: finalX,
                  y: finalY,
                  w: size,
                  h: size,
                  colorClass: colors[Math.floor(seededRandom(seed + 6) * colors.length)],
                  shape: shapes[Math.floor(seededRandom(seed + 7) * shapes.length)],
                  style: {
                      animationDuration: `${15 + seededRandom(seed + 3) * 15}s`,
                      animationDelay: `${seededRandom(seed + 4) * -15}s`,
                  },
              });
          }
      });
      return objects;
  }, [data?.slides]);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (audioRef.current) audioRef.current.pause();
    setIsPlaying(false);
    if (autoPlayTimerRef.current) window.clearTimeout(autoPlayTimerRef.current);

    const currentSlide = data?.slides?.[currentIndex];
    if (isAutoPlaying && currentIndex < totalSlides && currentSlide?.audioBase64) {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => {
            setIsPlaying(false);
            autoPlayTimerRef.current = window.setTimeout(nextSlide, 2000);
        };
        audioRef.current.play().then(() => setIsPlaying(true)).catch(e => console.warn("Audio play blocked", e));
    }
  }, [currentIndex, isAutoPlaying]);

  const toggleAudio = () => {
    const currentSlide = data?.slides?.[currentIndex];
    if (currentIndex >= totalSlides || !currentSlide?.audioBase64) return;
    if (audioRef.current && isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
    } else {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => setIsPlaying(false);
        audioRef.current.play();
        setIsPlaying(true);
    }
  };

  const handleManualNavigation = (action: () => void) => {
      setIsAutoPlaying(false);
      if (audioRef.current) audioRef.current.pause();
      action();
  };

  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); else setIsAutoPlaying(false); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleAiUpdate = async () => {
      const slide = data.slides[currentIndex];
      if (!slide || !aiUpdatePrompt.trim()) return;

      setIsUpdatingSlide(true);
      try {
          const updates = await updateSlideContent(slide, aiUpdatePrompt);
          onUpdateSlide(currentIndex, updates);
          if (updates.imagePrompt) {
              const newImg = await generateSlideImage(updates.imagePrompt);
              if (newImg) onUpdateSlide(currentIndex, { imageBase64: newImg });
          }
          if (updates.speakerNotes) {
              const newAudio = await generateSlideAudio(updates.speakerNotes);
              if (newAudio) onUpdateSlide(currentIndex, { audioBase64: newAudio });
          }
          setAiUpdatePrompt("");
      } catch (e) {
          console.error("AI update failed", e);
      } finally {
          setIsUpdatingSlide(false);
      }
  };

  const handleDownloadPPTX = () => generatePPTX({ ...data, presentationTitle: editableTitle });

  const handleDownloadHTML = () => {
    const html = generateHTMLPresentation({ ...data, presentationTitle: editableTitle }, exportOptions);
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const ext = exportOptions.format === 'aspx' ? 'aspx' : 'html';
    a.download = `${editableTitle.replace(/[^a-z0-9]/gi, '_')}.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setIsExportDialogOpen(false);
  };

  const estimatedSize = useMemo(() => {
    let size = 25000; // Base HTML + Scripts
    data.slides.forEach(s => {
        if (s.imageBase64) size += s.imageBase64.length;
        if (exportOptions.includeAudio && s.audioBase64) size += s.audioBase64.length;
        if (exportOptions.includeNotes && s.speakerNotes) size += s.speakerNotes.length * 2;
    });
    if (exportOptions.includeDecorations) size += 5000;
    if (exportOptions.includeAnimations) size += 2000;
    return (size / (1024 * 1024)).toFixed(2);
  }, [data, exportOptions]);

  const currentPos = currentIndex === totalSlides ? sourceCoords : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  const currentSlide = data?.slides?.[currentIndex];

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.4s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {decorObjects.map((obj) => (
             <div key={obj.id} className={`absolute ${obj.colorClass} ${obj.shape} animate-float-slow opacity-[0.12] pointer-events-none`} style={{ left: obj.x, top: obj.y, width: obj.w, height: obj.h, ...obj.style }} />
        ))}

        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            const isReversed = slide.layout === 'reversed';
            const hasImage = !!slide.imageBase64;
            const totalChars = (slide.bulletPoints || []).reduce((acc, curr) => acc + curr.length, 0) + slide.title.length;
            let fontSizeClass = totalChars > 400 ? 'text-sm' : 'text-lg';

            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 ease-in-out bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${isReversed && hasImage ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`${hasImage ? 'w-1/2 p-12' : 'w-full p-20 text-center'} flex flex-col justify-center`}>
                            <h3 className={`font-black text-white ${hasImage ? 'text-5xl' : 'text-6xl mb-12'} leading-tight mb-8`}>{slide.title}</h3>
                            <ul className="space-y-4">
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className="flex items-start">
                                        <span className="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span>
                                        <FormattedText text={bp} className={`${fontSizeClass} text-slate-200 leading-relaxed`} />
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {hasImage && (
                            <div className="w-1/2 p-8 h-full flex items-center justify-center">
                                <div className={`w-full h-full ${slide.shape || 'rounded-[3rem]'} overflow-hidden relative bg-slate-900 border border-white/10 shadow-2xl`}>
                                    <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover" alt={slide.title} />
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            );
        })}
      </div>

      {/* Control Overlay */}
      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none">
        <div className="pointer-events-auto flex gap-3">
           <button onClick={() => handleManualNavigation(onReset)} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 border border-white/10 shadow-xl hover:text-white transition-colors"><RefreshCw className="w-5 h-5" /></button>
           <button onClick={() => setShowNotes(!showNotes)} className={`w-11 h-11 flex items-center justify-center rounded-full border backdrop-blur-md transition-all ${showNotes ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}><FileText className="w-5 h-5" /></button>
        </div>
        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-none focus:outline-none w-full" />
            <div className="flex gap-2">
                <button onClick={() => setIsExportDialogOpen(true)} className="bg-slate-900/90 hover:bg-slate-800 text-slate-300 border border-white/10 px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-xl transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> EXPORT WEB</button>
                <button onClick={handleDownloadPPTX} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><Download className="w-4 h-4 mr-2" /> PPTX</button>
            </div>
        </div>
      </div>

      {/* Export Dialog */}
      {isExportDialogOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/70 backdrop-blur-md">
              <div className="w-full max-w-lg bg-slate-900/95 border border-white/10 rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-in">
                  <div className="p-8 border-b border-white/5 flex justify-between items-center bg-gradient-to-r from-blue-900/20 to-transparent">
                      <div>
                          <h3 className="text-2xl font-black text-white tracking-tight flex items-center">
                            <MonitorPlay className="w-6 h-6 mr-3 text-blue-500" /> Nastavení Exportu
                          </h3>
                          <p className="text-slate-400 text-sm mt-1">Přizpůsobte si webovou verzi pro odevzdání.</p>
                      </div>
                      <button onClick={() => setIsExportDialogOpen(false)} className="p-2 rounded-full hover:bg-white/5 transition-colors">
                          <X className="w-6 h-6 text-slate-500" />
                      </button>
                  </div>

                  <div className="p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="col-span-1 md:col-span-2 space-y-3">
                          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Formát souboru (Pro Teams vyber .aspx)</label>
                          <div className="grid grid-cols-2 gap-3">
                              <button 
                                onClick={() => setExportOptions(prev => ({ ...prev, format: 'html' }))}
                                className={`flex flex-col p-4 rounded-2xl border transition-all ${exportOptions.format === 'html' ? 'bg-blue-500/10 border-blue-500/50' : 'bg-slate-800/50 border-white/5 opacity-60'}`}
                              >
                                  <span className={`font-black text-lg ${exportOptions.format === 'html' ? 'text-blue-400' : 'text-slate-400'}`}>.HTML</span>
                                  <span className="text-[10px] text-slate-500 mt-1 uppercase font-bold tracking-tighter">Standardní Web</span>
                              </button>
                              <button 
                                onClick={() => setExportOptions(prev => ({ ...prev, format: 'aspx' }))}
                                className={`flex flex-col p-4 rounded-2xl border transition-all ${exportOptions.format === 'aspx' ? 'bg-indigo-500/10 border-indigo-500/50 shadow-[0_0_20px_rgba(99,102,241,0.15)]' : 'bg-slate-800/50 border-white/5 opacity-60'}`}
                              >
                                  <div className="flex justify-between items-start">
                                      <span className={`font-black text-lg ${exportOptions.format === 'aspx' ? 'text-indigo-400' : 'text-slate-400'}`}>.ASPX</span>
                                      {exportOptions.format === 'aspx' && <div className="bg-indigo-500 text-[8px] px-1.5 py-0.5 rounded text-white font-black">TEAMS OK</div>}
                                  </div>
                                  <span className="text-[10px] text-slate-500 mt-1 uppercase font-bold tracking-tighter">SharePoint / Teams</span>
                              </button>
                          </div>
                          {exportOptions.format === 'aspx' && (
                              <div className="flex items-start gap-3 p-3 bg-indigo-500/10 border border-indigo-500/20 rounded-xl">
                                  <Info className="w-4 h-4 text-indigo-400 mt-0.5 flex-shrink-0" />
                                  <p className="text-[10px] text-indigo-200 leading-normal">Tento formát umožní uciteli spustit prezentaci přímo v MS Teams bez stahování. Stačí soubor nahrát do složky "Soubory".</p>
                              </div>
                          )}
                      </div>

                      <div className="space-y-4">
                          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Zahrnout obsah</label>
                          <div className="space-y-2">
                              <ExportToggle label="Audio komentář" active={exportOptions.includeAudio} onClick={() => setExportOptions(p => ({...p, includeAudio: !p.includeAudio}))} icon={<Speaker className="w-3.5 h-3.5" />} />
                              <ExportToggle label="Poznámky řečníka" active={exportOptions.includeNotes} onClick={() => setExportOptions(p => ({...p, includeNotes: !p.includeNotes}))} icon={<FileText className="w-3.5 h-3.5" />} />
                              <ExportToggle label="Stránka zdrojů" active={exportOptions.includeSources} onClick={() => setExportOptions(p => ({...p, includeSources: !p.includeSources}))} icon={<ExternalLink className="w-3.5 h-3.5" />} />
                          </div>
                      </div>

                      <div className="space-y-4">
                          <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Vizuální optimalizace</label>
                          <div className="space-y-2">
                              <ExportToggle label="Plynulé animace" active={exportOptions.includeAnimations} onClick={() => setExportOptions(p => ({...p, includeAnimations: !p.includeAnimations}))} icon={<Zap className="w-3.5 h-3.5" />} />
                              <ExportToggle label="Dekorace pozadí" active={exportOptions.includeDecorations} onClick={() => setExportOptions(p => ({...p, includeDecorations: !p.includeDecorations}))} icon={<Layout className="w-3.5 h-3.5" />} />
                          </div>
                          <div className="p-3 bg-slate-950 rounded-xl flex items-center justify-between">
                              <div className="flex items-center gap-2">
                                  <HardDrive className="w-4 h-4 text-slate-600" />
                                  <span className="text-[10px] font-bold text-slate-500 uppercase">Velikost</span>
                              </div>
                              <span className={`text-xs font-black px-2 py-0.5 rounded ${parseFloat(estimatedSize) > 5 ? 'text-amber-500 bg-amber-500/10' : 'text-emerald-500 bg-emerald-500/10'}`}>{estimatedSize} MB</span>
                          </div>
                      </div>
                  </div>

                  <div className="p-8 pt-0 flex gap-4">
                      <button onClick={() => setIsExportDialogOpen(false)} className="flex-1 py-4 rounded-2xl font-bold text-slate-500 hover:text-white hover:bg-white/5 transition-all">Zrušit</button>
                      <button onClick={handleDownloadHTML} className="flex-[2] py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black shadow-xl shadow-blue-900/40 transition-all flex items-center justify-center gap-2">
                          STÁHNOUT SOUBOR <Download className="w-5 h-5" />
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Footer Nav */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onClick={() => handleManualNavigation(prevSlide)} disabled={currentIndex === 0} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronLeft className="w-6 h-6" /></button>
        <div className="text-white font-black text-xl w-20 text-center">{currentIndex + 1} <span className="text-slate-600">/ {totalPages}</span></div>
        <button onClick={() => handleManualNavigation(nextSlide)} disabled={currentIndex === totalPages - 1} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronRight className="w-6 h-6" /></button>
      </div>

      {/* Notes Drawer */}
      <div className={`fixed bottom-24 right-8 w-80 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl z-[60] transition-all duration-500 transform ${showNotes ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0 pointer-events-none'}`}>
          <div className="p-5 border-b border-white/5 flex justify-between items-center">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center"><FileText className="w-3.5 h-3.5 mr-2 text-indigo-400" /> Poznámky řečníka</h4>
              <button onClick={() => setShowNotes(false)} className="text-slate-500 hover:text-white transition-colors"><X className="w-4 h-4" /></button>
          </div>
          <div className="p-5 max-h-[300px] overflow-y-auto">
              <textarea className="w-full bg-transparent text-slate-300 text-sm leading-relaxed focus:outline-none resize-none min-h-[150px]" value={currentSlide?.speakerNotes || ""} onChange={(e) => onUpdateSlide(currentIndex, { speakerNotes: e.target.value })} />
          </div>
      </div>
    </div>
  );
};

const ExportToggle = ({ label, active, onClick, icon }: { label: string, active: boolean, onClick: () => void, icon: React.ReactNode }) => (
    <button onClick={onClick} className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${active ? 'bg-slate-800 border-white/10 text-slate-200' : 'bg-slate-950 border-transparent text-slate-600'}`}>
        <div className="flex items-center gap-3">
            <div className={`p-1.5 rounded-lg ${active ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-900 text-slate-700'}`}>{icon}</div>
            <span className="text-xs font-bold">{label}</span>
        </div>
        <div className={`w-3.5 h-3.5 rounded-full border-2 flex items-center justify-center transition-all ${active ? 'bg-blue-500 border-blue-500' : 'border-slate-800'}`}>
            {active && <Check className="w-2.5 h-2.5 text-white stroke-[4]" />}
        </div>
    </button>
);

import React, { useState, useRef } from 'react';
import { Upload, FileText, Image as ImageIcon, X, Sparkles, Mic, Play, Square, Eye, Layout } from 'lucide-react';
import { previewVoice } from '../services/geminiService';

interface InputSectionProps {
  topic: string;
  setTopic: (t: string) => void;
  slideCount: number;
  setSlideCount: (c: number) => void;
  voice: string;
  setVoice: (v: string) => void;
  files: File[];
  setFiles: (f: File[]) => void;
  onGenerate: () => void;
  onShowDemo: () => void;
  isGenerating: boolean;
}

export const InputSection: React.FC<InputSectionProps> = ({
  topic, setTopic, slideCount, setSlideCount, voice, setVoice, files, setFiles, onGenerate, onShowDemo, isGenerating
}) => {
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files);
      setFiles([...files, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(files.filter((_, i) => i !== index));
  };

  const handlePreviewVoice = async () => {
      if (isPreviewPlaying && audioRef.current) {
          audioRef.current.pause();
          setIsPreviewPlaying(false);
          return;
      }

      setIsPreviewLoading(true);
      const base64Audio = await previewVoice(voice);

      if (base64Audio) {
          if (audioRef.current) audioRef.current.pause();
          audioRef.current = new Audio(`data:audio/wav;base64,${base64Audio}`);
          audioRef.current.onended = () => setIsPreviewPlaying(false);
          audioRef.current.play();
          setIsPreviewPlaying(true);
      }
      setIsPreviewLoading(false);
  };

  const voices = [
    { id: 'Kore', name: 'Kore (Žena - Klidný)', gender: 'F' },
    { id: 'Fenrir', name: 'Fenrir (Muž - Hluboký)', gender: 'M' },
    { id: 'Puck', name: 'Puck (Neutrální)', gender: 'N' },
    { id: 'Aoede', name: 'Aoede (Žena - Jemný)', gender: 'F' },
    { id: 'Charon', name: 'Charon (Muž - Vážný)', gender: 'M' },
  ];

  return (
    <div className="w-full max-w-3xl mx-auto p-8 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl mt-10 animate-fade-in relative overflow-hidden">
      {/* Decorative background glow */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/10 rounded-full blur-3xl pointer-events-none -mr-16 -mt-16"></div>

      <div className="text-center mb-10 relative z-10">
        <div className="flex justify-center mb-4">
            <button 
                onClick={onShowDemo}
                className="group flex items-center gap-2 px-4 py-1.5 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-xs font-black uppercase tracking-widest hover:bg-blue-500/20 transition-all active:scale-95"
            >
                <Layout className="w-3.5 h-3.5" />
                Zobrazit ukázku rozložení
            </button>
        </div>
        <h1 className="text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-indigo-500 mb-4 tracking-tight">
          AI Student Presenter
        </h1>
        <p className="text-slate-400 text-lg">
          Zadej téma, vyber hlas, nahraj podklady a nech AI vytvořit moderní prezentaci.
        </p>
      </div>

      <div className="space-y-8 relative z-10">
        {/* Topic Input */}
        <div>
          <label className="block text-sm font-bold text-slate-300 mb-2 ml-1">TÉMA PREZENTACE</label>
          <textarea
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="Např. Historie renesance v Itálii, Fotosyntéza, nebo paste text zadání..."
            className="w-full h-36 bg-slate-950 border border-slate-700 rounded-2xl p-5 text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent focus:outline-none resize-none transition-all placeholder:text-slate-600 shadow-inner text-lg"
          />
        </div>

        {/* Controls Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          {/* Slider */}
          <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
            <label className="block text-sm font-bold text-slate-300 mb-4">
              POČET SLIDŮ: <span className="text-blue-400 text-xl ml-2">{slideCount}</span>
            </label>
            <input
              type="range"
              min="3"
              max="15"
              value={slideCount}
              onChange={(e) => setSlideCount(parseInt(e.target.value))}
              className="w-full h-3 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
            <div className="flex justify-between text-xs text-slate-500 mt-2 font-bold">
              <span>3</span>
              <span>15</span>
            </div>
          </div>

          {/* Voice Select */}
          <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800">
             <label className="block text-sm font-bold text-slate-300 mb-3 flex items-center">
                <Mic className="w-4 h-4 mr-2 text-blue-400"/> HLAS DABEŘE
             </label>
             <div className="flex gap-2">
                 <div className="relative flex-grow">
                    <select 
                        value={voice} 
                        onChange={(e) => { 
                            setVoice(e.target.value);
                            setIsPreviewPlaying(false);
                            if(audioRef.current) audioRef.current.pause();
                        }}
                        className="w-full bg-slate-900 border border-slate-700 text-white rounded-xl px-4 py-3 appearance-none focus:outline-none focus:border-blue-500 font-medium cursor-pointer hover:bg-slate-800 transition-colors"
                    >
                        {voices.map(v => (
                            <option key={v.id} value={v.id}>{v.name}</option>
                        ))}
                    </select>
                    <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none text-slate-500">
                        <svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" /></svg>
                    </div>
                 </div>

                 <button 
                    onClick={handlePreviewVoice}
                    disabled={isPreviewLoading}
                    className={`flex items-center justify-center w-12 h-[calc(100%-2px)] rounded-xl border transition-all ${
                        isPreviewPlaying 
                        ? 'bg-blue-500 border-blue-500 text-white' 
                        : 'bg-slate-800 border-slate-700 text-blue-400 hover:bg-slate-700 hover:text-white'
                    }`}
                    title="Vyzkoušet hlas"
                 >
                    {isPreviewLoading ? (
                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                    ) : isPreviewPlaying ? (
                        <Square className="w-4 h-4 fill-current" />
                    ) : (
                        <Play className="w-4 h-4 fill-current" />
                    )}
                 </button>
             </div>
          </div>

          {/* File Upload (Full Width on Desktop) */}
          <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 md:col-span-2">
            <label className="block text-sm font-bold text-slate-300 mb-3">PODKLADY (Obrázky, PDF)</label>
            <div className="relative h-20">
              <input
                type="file"
                multiple
                accept="image/*,application/pdf"
                onChange={handleFileChange}
                className="hidden"
                id="file-upload"
              />
              <label
                htmlFor="file-upload"
                className="flex items-center justify-center w-full h-full bg-slate-900 hover:bg-slate-800 border-2 border-slate-700 hover:border-blue-500 border-dashed rounded-xl cursor-pointer transition-all group"
              >
                <Upload className="w-5 h-5 text-slate-400 group-hover:text-blue-400 mr-2 transition-colors" />
                <span className="text-sm text-slate-400 group-hover:text-slate-200 font-medium">Nahrát soubory</span>
              </label>
            </div>
          </div>
        </div>

        {/* File List */}
        {files.length > 0 && (
          <div className="flex flex-wrap gap-2 p-4 bg-slate-950/50 rounded-2xl border border-slate-800">
            {files.map((file, index) => (
              <div key={index} className="flex items-center bg-slate-800 text-xs text-slate-200 px-3 py-1.5 rounded-full border border-slate-700 animate-fade-in-up">
                {file.type.includes('image') ? <ImageIcon className="w-3 h-3 mr-1.5 text-blue-400" /> : <FileText className="w-3 h-3 mr-1.5 text-red-400" />}
                <span className="max-w-[150px] truncate font-medium">{file.name}</span>
                <button onClick={() => removeFile(index)} className="ml-2 text-slate-500 hover:text-white transition-colors">
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
          </div>
        )}

        {/* Action Button */}
        <button
          onClick={onGenerate}
          disabled={!topic || isGenerating}
          className={`w-full py-5 rounded-2xl font-black text-xl flex items-center justify-center transition-all shadow-xl
            ${!topic || isGenerating 
              ? 'bg-slate-800 text-slate-600 cursor-not-allowed' 
              : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-900/30 hover:shadow-blue-900/50 hover:scale-[1.02] active:scale-[0.98]'
            }`}
        >
          {isGenerating ? (
            <>
              <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin mr-3"></div>
              Pracuji na tom...
            </>
          ) : (
            <>
              <Sparkles className="w-6 h-6 mr-2" />
              Vygenerovat prezentaci
            </>
          )}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { InputSection } from './components/InputSection';
import { LoadingScreen } from './components/LoadingScreen';
import { PresentationViewer } from './components/PresentationViewer';
import { AppState, PresentationData, Slide } from './types';
import { generatePresentationStructure, generateSlideImage, generateSlideAudio } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    step: 'input',
    topic: '',
    voice: 'Kore',
    slideCount: 5,
    files: [],
    filePreviews: [],
    presentation: null,
    currentSlideIndex: 0,
    loadingStatus: '',
    progress: 0
  });

  // Helpers for random initialization
  const getRandomShape = () => {
    const shapes = [
        'rounded-[3rem]', 
        'rounded-tl-[5rem] rounded-br-[5rem] rounded-tr-3xl rounded-bl-3xl', 
        'rounded-tl-3xl rounded-br-3xl rounded-tr-[5rem] rounded-bl-[5rem]', 
        'rounded-tl-[2rem] rounded-br-[2rem] rounded-tr-[6rem] rounded-bl-[6rem]',
        'rounded-[4rem] rounded-tr-none rounded-bl-none'
    ];
    return shapes[Math.floor(Math.random() * shapes.length)];
  };

  const getRandomLayout = (index: number) => {
      const layouts: Slide['layout'][] = ['classic', 'reversed', 'modern', 'immersive', 'minimal'];
      // Bias towards classic/reversed for readability
      if (index === 0) return 'immersive'; // Title slide
      if (Math.random() > 0.7) return layouts[Math.floor(Math.random() * layouts.length)];
      return index % 2 === 0 ? 'classic' : 'reversed';
  };

  const getCoordinates = (index: number) => {
      const colWidth = 1600;
      const rowHeight = 1000;
      const cols = 3; 

      const row = Math.floor(index / cols);
      const colPos = index % cols;
      const actualCol = row % 2 === 0 ? colPos : (cols - 1) - colPos;

      return {
          x: actualCol * colWidth + (Math.random() * 200 - 100),
          y: row * rowHeight + (Math.random() * 100 - 50)
      };
  };

  const handleShowDemo = () => {
    const demoSlides: Slide[] = [
        {
            id: 0,
            title: "Budoucnost AI ve Vzdělávání",
            bulletPoints: ["Personalizované učební plány", "Okamžitá zpětná vazba", "Virtuální asistenti pro studenty"],
            speakerNotes: "Vítejte u mé prezentace! Dnes si ukážeme, jak umělá inteligence mění způsob, jakým se učíme. AI není jen o generování textů, ale o podpoře kritického myšlení.",
            imagePrompt: "futuristic classroom with holograms and students using tablets, cinematic lighting",
            layout: 'immersive',
            shape: 'rounded-[3rem]',
            x: 0, y: 0
        },
        {
            id: 1,
            title: "Personalizace Výuky",
            bulletPoints: ["Tempo přizpůsobené jedinci", "Analýza silných a slabých stránek", "Automatická tvorba cvičení"],
            speakerNotes: "Každý student je jiný. AI dokáže identifikovat, kde má student mezery, a nabídnout mu přesně ty materiály, které mu pomohou látku pochopit.",
            imagePrompt: "digital human brain connected to circuit board, glowing neurons",
            layout: 'reversed',
            shape: 'rounded-tl-[5rem] rounded-br-[5rem]',
            x: 1600, y: 0
        },
        {
            id: 2,
            title: "Etické Otázky",
            bulletPoints: ["Zabezpečení dat", "Autenticita děl", "Dostupnost pro všechny"],
            speakerNotes: "Nesmíme zapomínat na rizika. Kdo vlastní data studentů? Jak zajistit, aby AI neprohlubovala rozdíly mezi bohatými a chudými školami?",
            imagePrompt: "scales of justice made of glowing blue code, dark background",
            layout: 'classic',
            shape: 'rounded-[4rem]',
            x: 3200, y: 0
        }
    ];

    setState(prev => ({
        ...prev,
        step: 'preview',
        presentation: {
            topic: "Demo Ukázka",
            presentationTitle: "Budoucnost AI ve Vzdělávání (DEMO)",
            slides: demoSlides,
            sources: [
                { title: "UNESCO AI Guide", uri: "https://unesco.org" },
                { title: "Future of Learning Lab", uri: "https://mit.edu" }
            ]
        }
    }));
  };

  const handleGenerateStructure = async () => {
    setState(prev => ({ ...prev, step: 'generating', loadingStatus: 'Analyzuji téma a navrhuji strukturu...', progress: 10 }));

    try {
      const { slides, sources, title } = await generatePresentationStructure(state.topic, state.slideCount, state.files);

      const processedSlides: Slide[] = slides.map((s, index) => {
          const coords = getCoordinates(index);
          return { 
            ...s,
            layout: getRandomLayout(index),
            shape: getRandomShape(),
            x: coords.x,
            y: coords.y,
            animation: 'pan'
          };
      });

      setState(prev => ({
        ...prev,
        step: 'preview',
        loadingStatus: 'Generuji na pozadí...',
        progress: 100,
        presentation: {
          topic: state.topic,
          presentationTitle: title, 
          slides: processedSlides,
          sources
        }
      }));

      generateContentBackground(processedSlides, state.voice);

    } catch (error) {
      console.error(error);
      alert("Chyba při generování.");
      setState(prev => ({ ...prev, step: 'input', loadingStatus: '', progress: 0 }));
    }
  };

  const generateContentBackground = async (slides: Slide[], voice: string) => {
      slides.forEach((slide, index) => {
          generateSlideImage(slide.imagePrompt).then(img => {
              if (img) {
                updateSlide(index, { imageBase64: img });
              }
          });
      });

      for (let i = 0; i < slides.length; i++) {
         try {
             setState(prev => ({ ...prev, loadingStatus: `Nahrávám hlas pro slide ${i + 1}...` }));
             const audio = await generateSlideAudio(slides[i].speakerNotes, voice);
             if (audio) {
                 updateSlide(i, { audioBase64: audio });
             }
             await new Promise(r => setTimeout(r, 500));
         } catch (e) {
             console.error(`Audio failed for slide ${i}`, e);
         }
      }
      setState(prev => ({ ...prev, loadingStatus: 'Hotovo.' }));
  };

  const updateSlide = (index: number, updates: Partial<Slide>) => {
      setState(currentState => {
          if (!currentState.presentation) return currentState;
          const newSlides = [...currentState.presentation.slides];
          if (newSlides[index]) {
              newSlides[index] = { ...newSlides[index], ...updates };
          }
          return {
              ...currentState,
              presentation: {
                  ...currentState.presentation,
                  slides: newSlides
              }
          };
      });
  };

  const handleReset = () => {
    setState(prev => ({ ...prev, step: 'input', presentation: null, progress: 0 }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white font-sans selection:bg-blue-500/30">
      {state.step === 'input' && (
        <div className="container mx-auto px-4 py-8">
            <InputSection 
              topic={state.topic} 
              setTopic={(t) => setState(prev => ({ ...prev, topic: t }))}
              slideCount={state.slideCount}
              setSlideCount={(c) => setState(prev => ({ ...prev, slideCount: c }))}
              voice={state.voice}
              setVoice={(v) => setState(prev => ({ ...prev, voice: v }))}
              files={state.files}
              setFiles={(f) => setState(prev => ({ ...prev, files: f }))}
              onGenerate={handleGenerateStructure}
              onShowDemo={handleShowDemo}
              isGenerating={false}
            />
        </div>
      )}

      {state.step === 'generating' && (
        <LoadingScreen status={state.loadingStatus} progress={state.progress} />
      )}

      {state.step === 'preview' && state.presentation && (
        <PresentationViewer 
            data={state.presentation}
            loadingStatus={state.loadingStatus}
            onReset={handleReset} 
            onUpdateSlide={updateSlide}
        />
      )}
    </div>
  );
};

export default App;

import { PresentationData } from "../types";

export interface ExportOptions {
  includeAudio: boolean;
  includeNotes: boolean;
  includeSources: boolean;
  includeAnimations: boolean;
  includeDecorations: boolean;
  format: 'html' | 'aspx';
}

export const generateHTMLPresentation = (data: PresentationData, options: ExportOptions) => {
  // Filtrace dat pro úsporu místa
  const filteredData = {
    ...data,
    slides: data.slides.map(s => ({
      ...s,
      audioBase64: options.includeAudio ? s.audioBase64 : undefined,
      speakerNotes: options.includeNotes ? s.speakerNotes : undefined
    })),
    sources: options.includeSources ? data.sources : []
  };

  const safeData = JSON.stringify(filteredData).replace(/</g, '\\u003c');
  const title = data?.presentationTitle || data?.topic || "Prezentace";
  const GAP_X = 1600;
  const GAP_Y_OFFSET = 1000;

  // Generování dekorací na pozadí jen pokud jsou povoleny
  const bgObjects = [];
  if (options.includeDecorations) {
    const colors = ['bg-blue-600', 'bg-indigo-700', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
    for (let i = 0; i <= data.slides.length; i++) {
        for (let j = 0; j < 4; j++) {
            const size = 80 + Math.random() * 200;
            const x = (i * GAP_X) + (Math.random() - 0.5) * 2400;
            const y = (i % 2 === 0 ? 0 : GAP_Y_OFFSET) + (Math.random() - 0.5) * 1800;
            const bg = colors[Math.floor(Math.random() * colors.length)];
            const animDur = 15 + Math.random() * 20;
            bgObjects.push(`<div class="absolute ${bg} rounded-3xl opacity-[0.12] ${options.includeAnimations ? 'animate-float' : ''} pointer-events-none" style="left:${x}px; top:${y}px; width:${size}px; height:${size}px; animation-duration:${animDur}s;"></div>`);
        }
    }
  }

  const slidesHtml = (data?.slides || []).map((slide, index) => {
      const x = index % 3 * GAP_X; 
      const y = Math.floor(index / 3) * GAP_Y_OFFSET;
      const hasImage = !!slide.imageBase64;
      const shapeClass = slide.shape || 'rounded-[3rem]';

      const formatText = (text: string) => {
          if (!text) return "";
          return text.split(/(\*\*.*?\*\*)/g).map(part => {
              if (part.startsWith('**') && part.endsWith('**')) {
                  return `<strong class="text-white">${part.slice(2, -2)}</strong>`;
              }
              return `<span>${part}</span>`;
          }).join('');
      };

      const bulletsHtml = (slide.bulletPoints || []).map((bp, idx) => `
          <li class="bullet-point ${options.includeAnimations ? 'opacity-0 translate-x-[-10px]' : ''} transition-all duration-700 flex items-start text-slate-200" style="transition-delay: ${idx * 100}ms">
              <span class="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500"></span>
              <span class="leading-relaxed text-lg">${formatText(bp)}</span>
          </li>`).join('');

      return `
      <div id="slide-${index}" class="slide-card absolute w-[1000px] h-[600px] bg-[#111827]/95 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${shapeClass} opacity-40 scale-95 blur-[1px] grayscale-[50%]" style="left: ${x}px; top: ${y}px;" onclick="goToSlide(${index})">
            <div class="flex w-full h-full ${slide.layout === 'reversed' && hasImage ? 'flex-row-reverse' : 'flex-row'} relative z-10">
                <div class="${hasImage ? 'w-1/2 p-14' : 'w-full p-20 text-center'} flex flex-col justify-center">
                    <h3 class="${hasImage ? 'text-5xl mb-8' : 'text-6xl mb-12'} font-black text-white leading-tight">${slide.title}</h3>
                    <ul class="space-y-6 ${!hasImage ? 'max-w-2xl mx-auto text-left' : ''}">${bulletsHtml}</ul>
                </div>
                ${hasImage ? `
                <div class="w-1/2 p-8 h-full flex items-center justify-center">
                    <div class="w-full h-full ${shapeClass} overflow-hidden bg-slate-900 border border-white/5 shadow-2xl">
                        <img src="data:image/png;base64,${slide.imageBase64}" class="w-full h-full object-cover" />
                    </div>
                </div>` : ''}
            </div>
      </div>`;
  }).join('');

  return `
<!DOCTYPE html>
<html lang="cs">
<head>
    <meta charset="UTF-8">
    <title>${title}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;700;900&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Outfit', sans-serif; background-color: #020617; overflow: hidden; perspective: 2000px; color: white; }
        .slide-card { transition: all ${options.includeAnimations ? '1.0s' : '0.1s'} cubic-bezier(0.2, 0, 0.2, 1); }
        .camera-view { transition: transform ${options.includeAnimations ? '1.4s' : '0.1s'} cubic-bezier(0.2, 0, 0.2, 1); transform-style: preserve-3d; }
        @keyframes float { 0%, 100% { transform: translate(0,0); } 50% { transform: translate(10px,-20px); } }
        .animate-float { animation: float 15s ease-in-out infinite; }
        .slide-active { opacity: 1 !important; transform: scale(1) !important; filter: none !important; blur: 0 !important; z-index: 50 !important; }
        .slide-active .bullet-point { opacity: 1 !important; transform: translateX(0) !important; }
        #notes-panel { transition: transform 0.4s ease, opacity 0.4s ease; transform: translateY(20px); opacity: 0; pointer-events: none; }
        #notes-panel.visible { transform: translateY(0); opacity: 1; pointer-events: auto; }
        .btn-active { color: #818cf8 !important; border-color: rgba(129, 140, 248, 0.4) !important; background: rgba(129, 140, 248, 0.1) !important; }
        .btn-disabled { opacity: 0.15 !important; pointer-events: none !important; }
    </style>
</head>
<body>
    <div id="camera" class="absolute top-0 left-0 w-full h-full camera-view">
        ${bgObjects.join('')}
        ${slidesHtml}
    </div>

    <!-- Panel poznámek -->
    <div id="notes-panel" class="fixed bottom-24 right-8 w-96 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl z-[100] p-6">
        <h4 class="text-xs font-black uppercase tracking-widest text-slate-400 mb-4 flex items-center">POZNÁMKY K PREZENTACI</h4>
        <div id="notes-content" class="text-slate-300 text-sm leading-relaxed max-h-64 overflow-y-auto pr-3 whitespace-pre-wrap"></div>
    </div>

    <!-- Ovládací lišta -->
    <div class="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onclick="prevSlide()" id="btn-prev" class="p-2 text-white hover:scale-125 transition-all"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m15 18-6-6 6-6"/></svg></button>
        <div class="font-black text-xl w-20 text-center flex items-center justify-center">
            <span id="curr">1</span><span class="text-slate-600 text-lg"> / ${data?.slides?.length || 0}</span>
        </div>
        <button onclick="nextSlide()" id="btn-next" class="p-2 text-white hover:scale-125 transition-all"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="m9 18 6-6-6-6"/></svg></button>

        <div class="w-px h-6 bg-white/10 mx-2"></div>

        <button onclick="toggleAudio()" id="btn-audio" class="p-2 text-slate-400 hover:text-white transition-all rounded-full border border-transparent" title="Audio">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"></path><path d="M15.54 8.46a5 5 0 0 1 0 7.07"></path><path d="M19.07 4.93a10 10 0 0 1 0 14.14"></path></svg>
        </button>

        <button onclick="toggleNotes()" id="btn-notes" class="p-2 text-slate-400 hover:text-white transition-all rounded-full border border-transparent" title="Poznámky">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path></svg>
        </button>
    </div>

    <script>
        const data = ${safeData};
        let currentIndex = 0;
        let notesVisible = false;
        let audio = new Audio();
        let isPlaying = false;

        function update() {
            const index = currentIndex;
            const slide = data.slides[index];
            if (!slide) return;
            const x = index % 3 * 1600;
            const y = Math.floor(index / 3) * 1000;
            const camX = (window.innerWidth/2) - x - 500;
            const camY = (window.innerHeight/2) - y - 300;

            document.getElementById('camera').style.transform = \`translate3d(\${camX}px, \${camY}px, 0)\`;

            for(let i=0; i<data.slides.length; i++) {
                const el = document.getElementById('slide-'+i);
                if(el) {
                  el.classList.remove('slide-active');
                  if(i === index) el.classList.add('slide-active');
                }
            }

            document.getElementById('curr').innerText = index + 1;
            document.getElementById('btn-prev').classList.toggle('opacity-20', index === 0);
            document.getElementById('btn-next').classList.toggle('opacity-20', index === data.slides.length - 1);

            document.getElementById('notes-content').textContent = slide.speakerNotes || 'K tomuto slidu nejsou poznámky.';

            const btnAudio = document.getElementById('btn-audio');
            const btnNotes = document.getElementById('btn-notes');
            btnAudio.classList.toggle('btn-disabled', !slide.audioBase64);
            btnNotes.classList.toggle('btn-disabled', !slide.speakerNotes);

            stopAudio();
        }

        function toggleNotes() {
            notesVisible = !notesVisible;
            document.getElementById('notes-panel').classList.toggle('visible', notesVisible);
            document.getElementById('btn-notes').classList.toggle('btn-active', notesVisible);
        }

        function toggleAudio() {
            const slide = data.slides[currentIndex];
            if (!slide.audioBase64) return;
            if (isPlaying) { stopAudio(); } 
            else {
                audio.src = "data:audio/wav;base64," + slide.audioBase64;
                audio.play();
                isPlaying = true;
                document.getElementById('btn-audio').classList.add('btn-active');
                audio.onended = stopAudio;
            }
        }

        function stopAudio() {
            audio.pause();
            isPlaying = false;
            document.getElementById('btn-audio').classList.remove('btn-active');
        }

        function nextSlide() { if(currentIndex < data.slides.length-1) { currentIndex++; update(); } }
        function prevSlide() { if(currentIndex > 0) { currentIndex--; update(); } }
        function goToSlide(i) { currentIndex = i; update(); }

        window.addEventListener('keydown', e => { 
            if(e.key==='ArrowRight' || e.key===' ') nextSlide(); 
            if(e.key==='ArrowLeft') prevSlide(); 
        });

        update();
    </script>
</body>
</html>`;
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, PlayCircle, Speaker, MonitorPlay, Sparkles, ExternalLink, Wand2, FileText, Send, Loader2, X, Info, Check, HardDrive, Zap, Layout, Trash2 } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation, ExportOptions } from '../services/htmlExportService';
import { updateSlideContent, generateSlideImage, generateSlideAudio } from '../services/geminiService';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  if (!text) return null;
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return (
    <span className={className}>
      {parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="font-black text-white bg-blue-500/10 px-1 rounded-sm">{part.slice(2, -2)}</strong>;
        }
        return <span key={i} className="font-medium opacity-90">{part}</span>;
      })}
    </span>
  );
};

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const [showNotes, setShowNotes] = useState(false);
  const [aiUpdatePrompt, setAiUpdatePrompt] = useState("");
  const [isUpdatingSlide, setIsUpdatingSlide] = useState(false);
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);

  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    includeAudio: true,
    includeNotes: true,
    includeSources: true,
    includeAnimations: true,
    includeDecorations: true,
    format: 'html'
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoPlayTimerRef = useRef<number | null>(null);
  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const totalSlides = data?.slides?.length || 0;
  const lastSlide = data?.slides?.[totalSlides - 1];
  const sourceCoords = { x: (lastSlide?.x || 0) + 1600, y: (lastSlide?.y || 0) }; 
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  const decorObjects = useMemo(() => {
      const objects: any[] = [];
      const colors = ['bg-blue-600', 'bg-blue-800', 'bg-sky-500', 'bg-slate-700', 'bg-blue-900'];
      const shapes = ['rounded-full', 'rounded-3xl', 'rounded-xl'];
      const allSlides = [...(data?.slides || []).map(s => ({ x: s.x, y: s.y })), { x: sourceCoords.x, y: sourceCoords.y }];

      allSlides.forEach((slide, idx) => {
          for (let i = 0; i < 6; i++) {
              const seed = idx * 100 + i;
              const size = 60 + seededRandom(seed) * 180;
              const finalX = (slide.x || 0) + (seededRandom(seed + 1) - 0.5) * 2400;
              const finalY = (slide.y || 0) + (seededRandom(seed + 2) - 0.5) * 1800;

              objects.push({
                  id: `decor-${idx}-${i}`,
                  x: finalX,
                  y: finalY,
                  w: size,
                  h: size,
                  colorClass: colors[Math.floor(seededRandom(seed + 6) * colors.length)],
                  shape: shapes[Math.floor(seededRandom(seed + 7) * shapes.length)],
                  style: {
                      animationDuration: `${15 + seededRandom(seed + 3) * 15}s`,
                      animationDelay: `${seededRandom(seed + 4) * -15}s`,
                  },
              });
          }
      });
      return objects;
  }, [data?.slides]);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (audioRef.current) audioRef.current.pause();
    setIsPlaying(false);
    if (autoPlayTimerRef.current) window.clearTimeout(autoPlayTimerRef.current);

    const currentSlide = data?.slides?.[currentIndex];
    if (isAutoPlaying && currentIndex < totalSlides && currentSlide?.audioBase64) {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => {
            setIsPlaying(false);
            autoPlayTimerRef.current = window.setTimeout(nextSlide, 2000);
        };
        audioRef.current.play().then(() => setIsPlaying(true)).catch(e => console.warn("Audio play blocked", e));
    }
  }, [currentIndex, isAutoPlaying]);

  const toggleAudio = () => {
    const currentSlide = data?.slides?.[currentIndex];
    if (currentIndex >= totalSlides || !currentSlide?.audioBase64) return;
    if (audioRef.current && isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
    } else {
        audioRef.current = new Audio(`data:audio/wav;base64,${currentSlide.audioBase64}`);
        audioRef.current.onended = () => setIsPlaying(false);
        audioRef.current.play();
        setIsPlaying(true);
    }
  };

  const handleManualNavigation = (action: () => void) => {
      setIsAutoPlaying(false);
      if (audioRef.current) audioRef.current.pause();
      action();
  };

  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); else setIsAutoPlaying(false); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleAiUpdate = async () => {
      const slide = data.slides[currentIndex];
      if (!slide || !aiUpdatePrompt.trim()) return;

      setIsUpdatingSlide(true);
      try {
          const updates = await updateSlideContent(slide, aiUpdatePrompt);
          onUpdateSlide(currentIndex, updates);
          if (updates.imagePrompt) {
              const newImg = await generateSlideImage(updates.imagePrompt);
              if (newImg) onUpdateSlide(currentIndex, { imageBase64: newImg });
          }
          if (updates.speakerNotes) {
              const newAudio = await generateSlideAudio(updates.speakerNotes);
              if (newAudio) onUpdateSlide(currentIndex, { audioBase64: newAudio });
          }
          setAiUpdatePrompt("");
      } catch (e) {
          console.error("AI update failed", e);
      } finally {
          setIsUpdatingSlide(false);
      }
  };

  const handleDownloadPPTX = () => generatePPTX({ ...data, presentationTitle: editableTitle });

  const handleDownloadHTML = () => {
    const html = generateHTMLPresentation({ ...data, presentationTitle: editableTitle }, exportOptions);
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const ext = exportOptions.format === 'aspx' ? 'aspx' : 'html';
    a.download = `${editableTitle.replace(/[^a-z0-9]/gi, '_')}.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setIsExportDialogOpen(false);
  };

  // Výpočet odhadované velikosti pro učitele (Teams má limity na nahrávání u některých projektů)
  const estimatedSize = useMemo(() => {
    let size = 35000; // Základní kód a styly
    data.slides.forEach(s => {
        if (s.imageBase64) size += s.imageBase64.length;
        if (exportOptions.includeAudio && s.audioBase64) size += s.audioBase64.length;
        if (exportOptions.includeNotes && s.speakerNotes) size += s.speakerNotes.length * 1.5;
    });
    if (exportOptions.includeDecorations) size += 8000;
    return (size / (1024 * 1024)).toFixed(2);
  }, [data, exportOptions]);

  const applySpaceSaver = () => {
      setExportOptions({
          includeAudio: false,
          includeNotes: true,
          includeSources: true,
          includeAnimations: false,
          includeDecorations: false,
          format: 'html'
      });
  };

  const currentPos = currentIndex === totalSlides ? sourceCoords : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  const currentSlide = data?.slides?.[currentIndex];

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.4s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {decorObjects.map((obj) => (
             <div key={obj.id} className={`absolute ${obj.colorClass} ${obj.shape} animate-float-slow opacity-[0.12] pointer-events-none`} style={{ left: obj.x, top: obj.y, width: obj.w, height: obj.h, ...obj.style }} />
        ))}

        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            const hasImage = !!slide.imageBase64;
            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 ease-in-out bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${slide.layout === 'reversed' && hasImage ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`${hasImage ? 'w-1/2 p-12' : 'w-full p-20 text-center'} flex flex-col justify-center`}>
                            <h3 className="font-black text-white text-5xl leading-tight mb-8">{slide.title}</h3>
                            <ul className="space-y-4">
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className="flex items-start">
                                        <span className="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span>
                                        <FormattedText text={bp} className="text-lg text-slate-200 leading-relaxed" />
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {hasImage && (
                            <div className="w-1/2 p-8 h-full flex items-center justify-center">
                                <div className={`w-full h-full ${slide.shape || 'rounded-[3rem]'} overflow-hidden relative bg-slate-900 border border-white/10 shadow-2xl`}>
                                    <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover" alt={slide.title} />
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            );
        })}
      </div>

      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none">
        <div className="pointer-events-auto flex gap-3">
           <button onClick={() => handleManualNavigation(onReset)} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 border border-white/10 shadow-xl hover:text-white transition-colors"><RefreshCw className="w-5 h-5" /></button>
           <button onClick={() => setShowNotes(!showNotes)} className={`w-11 h-11 flex items-center justify-center rounded-full border backdrop-blur-md transition-all ${showNotes ? 'bg-indigo-600 border-indigo-500 text-white shadow-xl' : 'bg-slate-900/90 border-white/10 text-slate-400 hover:text-white'}`}><FileText className="w-5 h-5" /></button>
        </div>
        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-none focus:outline-none w-full" />
            <div className="flex gap-2">
                <button onClick={() => setIsExportDialogOpen(true)} className="bg-slate-900/90 hover:bg-slate-800 text-slate-300 border border-white/10 px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-xl transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> EXPORT WEB</button>
                <button onClick={handleDownloadPPTX} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><Download className="w-4 h-4 mr-2" /> PPTX</button>
            </div>
        </div>
      </div>

      {isExportDialogOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/70 backdrop-blur-md">
              <div className="w-full max-w-lg bg-slate-900/95 border border-white/10 rounded-[2.5rem] shadow-2xl overflow-hidden animate-scale-in">
                  <div className="p-8 border-b border-white/5 flex justify-between items-center">
                      <div>
                          <h3 className="text-2xl font-black text-white tracking-tight flex items-center">
                            <MonitorPlay className="w-6 h-6 mr-3 text-blue-500" /> Exportovat do Webu
                          </h3>
                          <p className="text-slate-400 text-sm mt-1">Nastavení verze pro odevzdání (vhodné pro Teams).</p>
                      </div>
                      <button onClick={() => setIsExportDialogOpen(false)} className="p-2 rounded-full hover:bg-white/5 transition-colors">
                          <X className="w-6 h-6 text-slate-500" />
                      </button>
                  </div>

                  <div className="p-8 space-y-6">
                      <div className="grid grid-cols-2 gap-4">
                          <ExportToggle label="Audio výklad" active={exportOptions.includeAudio} onClick={() => setExportOptions(p => ({...p, includeAudio: !p.includeAudio}))} icon={<Speaker className="w-4 h-4" />} />
                          <ExportToggle label="Poznámky" active={exportOptions.includeNotes} onClick={() => setExportOptions(p => ({...p, includeNotes: !p.includeNotes}))} icon={<FileText className="w-4 h-4" />} />
                          <ExportToggle label="Animace" active={exportOptions.includeAnimations} onClick={() => setExportOptions(p => ({...p, includeAnimations: !p.includeAnimations}))} icon={<Zap className="w-4 h-4" />} />
                          <ExportToggle label="Grafika pozadí" active={exportOptions.includeDecorations} onClick={() => setExportOptions(p => ({...p, includeDecorations: !p.includeDecorations}))} icon={<Layout className="w-4 h-4" />} />
                      </div>

                      <div className="flex items-center justify-between p-4 bg-slate-950 rounded-2xl border border-white/5">
                          <div className="flex items-center gap-3">
                              <HardDrive className="w-5 h-5 text-slate-500" />
                              <div className="text-xs">
                                  <span className="block font-bold text-slate-400 uppercase tracking-widest">Velikost souboru</span>
                                  <span className="text-slate-500">Odhadovaná velikost verze</span>
                              </div>
                          </div>
                          <span className={`text-lg font-black ${parseFloat(estimatedSize) > 8 ? 'text-amber-500' : 'text-emerald-500'}`}>{estimatedSize} MB</span>
                      </div>

                      <div className="flex gap-2">
                        <button onClick={applySpaceSaver} className="flex-1 py-3 px-4 rounded-xl border border-amber-500/20 bg-amber-500/5 text-amber-500 text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-amber-500/10 transition-all">
                            <Trash2 className="w-3 h-3" /> Úsporný režim
                        </button>
                        <div className="flex-grow flex items-center gap-2 px-4 rounded-xl bg-blue-500/5 border border-blue-500/20">
                            <Info className="w-4 h-4 text-blue-400" />
                            <p className="text-[9px] text-blue-200 leading-tight italic">Úsporný režim vypne audio a grafiku pro bleskové nahrávání do Teams.</p>
                        </div>
                      </div>
                  </div>

                  <div className="p-8 pt-0 flex gap-4">
                      <button onClick={() => setIsExportDialogOpen(false)} className="flex-1 py-4 rounded-2xl font-bold text-slate-500 hover:text-white hover:bg-white/5 transition-all">Zrušit</button>
                      <button onClick={handleDownloadHTML} className="flex-[2] py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black shadow-xl shadow-blue-900/40 transition-all flex items-center justify-center gap-2">
                          STÁHNOUT WEB <Download className="w-5 h-5" />
                      </button>
                  </div>
              </div>
          </div>
      )}

      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onClick={() => handleManualNavigation(prevSlide)} disabled={currentIndex === 0} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronLeft className="w-6 h-6" /></button>
        <div className="text-white font-black text-xl w-20 text-center">{currentIndex + 1} <span className="text-slate-600">/ {totalPages}</span></div>
        <button onClick={() => handleManualNavigation(nextSlide)} disabled={currentIndex === totalPages - 1} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronRight className="w-6 h-6" /></button>
      </div>

      <div className={`fixed bottom-24 right-8 w-80 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl shadow-2xl z-[60] transition-all duration-500 transform ${showNotes ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0 pointer-events-none'}`}>
          <div className="p-5 border-b border-white/5 flex justify-between items-center">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 flex items-center"><FileText className="w-3.5 h-3.5 mr-2 text-indigo-400" /> Poznámky řečníka</h4>
              <button onClick={() => setShowNotes(false)} className="text-slate-500 hover:text-white transition-colors"><X className="w-4 h-4" /></button>
          </div>
          <div className="p-5 max-h-[300px] overflow-y-auto">
              <textarea className="w-full bg-transparent text-slate-300 text-sm leading-relaxed focus:outline-none resize-none min-h-[150px]" value={currentSlide?.speakerNotes || ""} onChange={(e) => onUpdateSlide(currentIndex, { speakerNotes: e.target.value })} />
          </div>
      </div>
    </div>
  );
};

const ExportToggle = ({ label, active, onClick, icon }: { label: string, active: boolean, onClick: () => void, icon: React.ReactNode }) => (
    <button onClick={onClick} className={`w-full flex items-center justify-between p-3 rounded-2xl border transition-all ${active ? 'bg-slate-800 border-white/10 text-slate-200' : 'bg-slate-950 border-transparent text-slate-600'}`}>
        <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl ${active ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-900 text-slate-700'}`}>{icon}</div>
            <span className="text-[11px] font-bold text-left">{label}</span>
        </div>
        <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-all ${active ? 'bg-blue-500 border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]' : 'border-slate-800'}`}>
            {active && <Check className="w-2.5 h-2.5 text-white stroke-[4]" />}
        </div>
    </button>
);

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, PlayCircle, Speaker, MonitorPlay, Sparkles, ExternalLink, Wand2, FileText, Send, Loader2, X, Info, Check, HardDrive, Zap, Layout, Trash2, Printer, AlertCircle } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation, ExportOptions } from '../services/htmlExportService';
import { updateSlideContent, generateSlideImage, generateSlideAudio } from '../services/geminiService';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

const FormattedText: React.FC<{ text: string; className?: string }> = ({ text, className = "" }) => {
  if (!text) return null;
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return (
    <span className={className}>
      {parts.map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="font-black text-white bg-blue-500/10 px-1 rounded-sm">{part.slice(2, -2)}</strong>;
        }
        return <span key={i} className="font-medium opacity-90">{part}</span>;
      })}
    </span>
  );
};

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const [showNotes, setShowNotes] = useState(false);
  const [aiUpdatePrompt, setAiUpdatePrompt] = useState("");
  const [isUpdatingSlide, setIsUpdatingSlide] = useState(false);
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
  const [exportTab, setExportTab] = useState<'files' | 'guide'>('files');

  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    includeAudio: true,
    includeNotes: true,
    includeSources: true,
    includeAnimations: true,
    includeDecorations: true,
    format: 'html'
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const autoPlayTimerRef = useRef<number | null>(null);
  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });

  const totalSlides = data?.slides?.length || 0;
  const lastSlide = data?.slides?.[totalSlides - 1];
  const sourceCoords = { x: (lastSlide?.x || 0) + 1600, y: (lastSlide?.y || 0) }; 
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleDownloadPPTX = () => generatePPTX({ ...data, presentationTitle: editableTitle });

  const handlePrintPDF = () => {
      window.print(); // Otevře systémové okno pro tisk, kde uživatel vybere "Uložit jako PDF"
  };

  const handleDownloadHTML = () => {
    const html = generateHTMLPresentation({ ...data, presentationTitle: editableTitle }, exportOptions);
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const ext = exportOptions.format === 'aspx' ? 'aspx' : 'html';
    a.download = `${editableTitle.replace(/[^a-z0-9]/gi, '_')}.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    setIsExportDialogOpen(false);
  };

  const currentPos = currentIndex === totalSlides ? sourceCoords : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  const currentSlide = data?.slides?.[currentIndex];

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      {/* Skryté elementy pro tisk do PDF */}
      <div className="hidden print:block print:bg-white print:text-black">
          {data.slides.map((slide, i) => (
              <div key={i} className="h-screen w-screen p-10 flex flex-col justify-center border-b border-gray-200 page-break-after-always">
                  <h1 className="text-4xl font-bold mb-8 text-blue-800">{slide.title}</h1>
                  <ul className="list-disc list-inside space-y-4">
                      {slide.bulletPoints.map((bp, j) => <li key={j} className="text-2xl text-gray-700">{bp}</li>)}
                  </ul>
                  {slide.speakerNotes && <div className="mt-10 p-4 bg-gray-100 border-l-4 border-blue-500 text-sm italic">{slide.speakerNotes}</div>}
              </div>
          ))}
      </div>

      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.4s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d print:hidden" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            const hasImage = !!slide.imageBase64;
            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 ease-in-out bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50 border-white/10' : 'opacity-40 scale-95 grayscale-[50%] z-10 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${slide.layout === 'reversed' && hasImage ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`${hasImage ? 'w-1/2 p-12' : 'w-full p-20 text-center'} flex flex-col justify-center`}>
                            <h3 className="font-black text-white text-5xl leading-tight mb-8">{slide.title}</h3>
                            <ul className="space-y-4">
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className="flex items-start">
                                        <span className="w-2 h-2 rounded-full mt-2.5 mr-4 flex-shrink-0 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span>
                                        <FormattedText text={bp} className="text-lg text-slate-200 leading-relaxed" />
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {hasImage && (
                            <div className="w-1/2 p-8 h-full flex items-center justify-center">
                                <div className={`w-full h-full ${slide.shape || 'rounded-[3rem]'} overflow-hidden relative bg-slate-900 border border-white/10 shadow-2xl`}>
                                    <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover" alt={slide.title} />
                                </div>
