      </div>

      {/* Ovládání */}
      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none print:hidden">
        <div className="pointer-events-auto flex gap-3">
           <button onClick={onReset} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 border border-white/10 shadow-xl hover:text-white transition-colors"><RefreshCw className="w-5 h-5" /></button>
        </div>
        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-none focus:outline-none w-full" />
            <div className="flex gap-2">
                <button onClick={() => setIsExportDialogOpen(true)} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> Odevzdat práci</button>
