import React, { useState, useEffect, useRef } from 'react';
import { PresentationData, Slide } from '../types';
import { ChevronLeft, ChevronRight, Download, RefreshCw, MonitorPlay, Wand2, X, Info, Layout, Printer, Image as ImageIcon, CheckCircle2, AlertTriangle, Upload, Sparkles, Loader2, Save } from 'lucide-react';
import { generatePPTX } from '../services/pptxService';
import { generateHTMLPresentation, ExportOptions } from '../services/htmlExportService';
import { updateSlideContent, generateSlideImage, validateImage, generateSlideAudio } from '../services/geminiService';
import html2canvas from 'html2canvas';
import JSZip from 'jszip';

interface PresentationViewerProps {
  data: PresentationData;
  loadingStatus: string;
  onReset: () => void;
  onUpdateSlide: (index: number, updates: Partial<Slide>) => void;
}

export const PresentationViewer: React.FC<PresentationViewerProps> = ({ data, loadingStatus, onReset, onUpdateSlide }) => {
  const [editableTitle, setEditableTitle] = useState(data?.presentationTitle || data?.topic || "Prezentace");
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
  const [exportTab, setExportTab] = useState<'files' | 'guide'>('files');
  const [isEditing, setIsEditing] = useState(false);
  const [aiUpdatePrompt, setAiUpdatePrompt] = useState("");
  const [isUpdating, setIsUpdating] = useState(false);

  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    includeAudio: true, includeNotes: true, includeSources: true,
    includeAnimations: true, includeDecorations: true, format: 'html'
  });

  const [viewportSize, setViewportSize] = useState({ w: window.innerWidth, h: window.innerHeight });
  const totalSlides = data?.slides?.length || 0;
  const totalPages = totalSlides + ((data?.sources?.length || 0) > 0 ? 1 : 0);

  useEffect(() => {
    const handleResize = () => setViewportSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const currentSlide = data?.slides?.[currentIndex];
  const nextSlide = () => { if (currentIndex < totalPages - 1) setCurrentIndex(prev => prev + 1); };
  const prevSlide = () => { if (currentIndex > 0) setCurrentIndex(prev => prev - 1); };

  const handleDownloadImages = async () => {
    const zip = new JSZip();
    const slidesElements = document.querySelectorAll('.slide-card-raw');

    setIsUpdating(true);
    for (let i = 0; i < slidesElements.length; i++) {
        const canvas = await html2canvas(slidesElements[i] as HTMLElement, { backgroundColor: '#020617', scale: 2 });
        const dataUrl = canvas.toDataURL('image/png').split(',')[1];
        zip.file(`slide_${i + 1}.png`, dataUrl, { base64: true });
    }
    const content = await zip.generateAsync({ type: 'blob' });
    const url = URL.createObjectURL(content);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${editableTitle}_fotky.zip`;
    a.click();
    setIsUpdating(false);
    setIsExportDialogOpen(false);
  };

  const handleUpdateSlideAI = async () => {
    if (!currentSlide || !aiUpdatePrompt) return;
    setIsUpdating(true);
    const updates = await updateSlideContent(currentSlide, aiUpdatePrompt);
    onUpdateSlide(currentIndex, updates);
    setAiUpdatePrompt("");
    setIsUpdating(false);
  };

  const handleRegenerateImage = async () => {
      if (!currentSlide) return;
      setIsUpdating(true);
      const img = await generateSlideImage(currentSlide.imagePrompt);
      if (img) {
          const validation = await validateImage(img, currentSlide.title, currentSlide.bulletPoints);
          onUpdateSlide(currentIndex, { imageBase64: img, imageValidation: validation });
      }
      setIsUpdating(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (ev) => {
              const base64 = ev.target?.result?.toString().split(',')[1];
              if (base64) onUpdateSlide(currentIndex, { imageBase64: base64, imageValidation: undefined });
          };
          reader.readAsDataURL(file);
      }
  };

  const currentPos = currentIndex === totalSlides ? { x: (data?.slides?.[totalSlides-1]?.x || 0) + 1600, y: (data?.slides?.[totalSlides-1]?.y || 0) } : { x: data?.slides?.[currentIndex]?.x || 0, y: data?.slides?.[currentIndex]?.y || 0 };
  const cameraX = (viewportSize.w / 2) - currentPos.x - 500;
  const cameraY = (viewportSize.h / 2) - currentPos.y - 300;

  return (
    <div className="fixed inset-0 bg-[#020617] overflow-hidden flex flex-col font-sans perspective-[2000px]">
      {/* Skryté elementy pro export fotek */}
      <div className="fixed -left-[2000px] top-0 pointer-events-none">
          {data.slides.map((slide, i) => (
              <div key={i} id={`raw-slide-${i}`} className="slide-card-raw w-[1000px] h-[600px] bg-[#111827] flex overflow-hidden p-10 border border-white/5">
                   <div className={`flex w-full h-full ${slide.layout === 'reversed' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className="w-1/2 p-10 flex flex-col justify-center">
                            <h2 className="text-white text-5xl font-black mb-8 leading-tight">{slide.title}</h2>
                            <ul className="space-y-4">
                                {slide.bulletPoints.map((bp, j) => (
                                    <li key={j} className="text-slate-200 text-xl flex items-start">
                                        <span className="w-2 h-2 bg-blue-500 rounded-full mr-4 mt-2"></span> {bp}
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {slide.imageBase64 && (
                            <div className="w-1/2 p-10 h-full">
                                <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover rounded-[3rem]" />
                            </div>
                        )}
                   </div>
              </div>
          ))}
      </div>

      <div className="absolute top-0 left-0 w-full h-full transition-transform duration-[1.2s] cubic-bezier(0.2, 0, 0.2, 1) transform-style-3d" style={{ transform: `translate3d(${cameraX}px, ${cameraY}px, 0)` }}>
        {(data?.slides || []).map((slide, index) => {
            const isActive = index === currentIndex;
            return (
                <div key={index} className={`absolute w-[1000px] h-[600px] transition-all duration-1000 bg-[#111827]/90 backdrop-blur-3xl border border-white/5 overflow-hidden flex shadow-2xl ${slide.shape || 'rounded-[3rem]'} ${isActive ? 'opacity-100 scale-100 z-50' : 'opacity-40 scale-95 blur-[1px]'}`} style={{ left: slide.x || 0, top: slide.y || 0 }}>
                    <div className={`flex w-full h-full ${slide.layout === 'reversed' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className="w-1/2 p-14 flex flex-col justify-center">
                            <h3 className="font-black text-white text-5xl leading-tight mb-8">{slide.title}</h3>
                            <ul className="space-y-4">
                                {(slide.bulletPoints || []).map((bp, idx) => (
                                    <li key={idx} className="flex items-start text-lg text-slate-200 leading-relaxed">
                                        <span className="w-2 h-2 rounded-full mt-2.5 mr-4 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></span> {bp}
                                    </li>
                                ))}
                            </ul>
                        </div>
                        {slide.imageBase64 && (
                            <div className="w-1/2 p-8 h-full flex items-center justify-center relative">
                                <img src={`data:image/png;base64,${slide.imageBase64}`} className="w-full h-full object-cover rounded-[3rem] shadow-2xl" />
                                {slide.imageValidation && (
                                    <div className={`absolute bottom-12 right-12 px-4 py-2 rounded-full backdrop-blur-xl border flex items-center gap-2 shadow-xl ${slide.imageValidation.isOk ? 'bg-emerald-500/20 border-emerald-500/50 text-emerald-400' : 'bg-red-500/20 border-red-500/50 text-red-400'}`}>
                                        {slide.imageValidation.isOk ? <CheckCircle2 className="w-4 h-4"/> : <AlertTriangle className="w-4 h-4"/>}
                                        <span className="text-[10px] font-black uppercase tracking-widest">{slide.imageValidation.isOk ? 'AI Ověřeno' : 'AI Varování'}</span>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            );
        })}
      </div>

      {/* Editor Panel */}
      {isEditing && currentSlide && (
          <div className="absolute right-0 top-0 h-full w-96 bg-slate-900 border-l border-white/10 z-[60] shadow-2xl animate-slide-in-right flex flex-col p-8">
              <div className="flex justify-between items-center mb-8">
                  <h4 className="text-white font-black text-xl flex items-center gap-2"><Wand2 className="w-5 h-5 text-blue-500"/> Upravit slide</h4>
                  <button onClick={() => setIsEditing(false)} className="text-slate-500 hover:text-white"><X/></button>
              </div>

              <div className="flex-grow space-y-8 overflow-y-auto pr-2">
                  <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Co chceš změnit?</label>
                      <textarea 
                        value={aiUpdatePrompt}
                        onChange={(e) => setAiUpdatePrompt(e.target.value)}
                        placeholder="Napiš např: 'Změň obrázek na více futuristický' nebo 'Přidej odrážku o historii'."
                        className="w-full h-32 bg-slate-950 border border-slate-800 rounded-2xl p-4 text-sm text-white focus:outline-none focus:border-blue-500 resize-none transition-all"
                      />
                      <button 
                        onClick={handleUpdateSlideAI} 
                        disabled={isUpdating || !aiUpdatePrompt}
                        className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white font-black rounded-xl text-xs uppercase tracking-widest flex items-center justify-center gap-2 disabled:opacity-50 transition-all"
                      >
                          {isUpdating ? <Loader2 className="animate-spin w-4 h-4"/> : <Sparkles className="w-4 h-4"/>} Upravit pomocí AI
                      </button>
                  </div>

                  <div className="space-y-4 border-t border-white/5 pt-6">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Obrázek a vizuály</label>
                      <div className="grid grid-cols-2 gap-3">
                          <button onClick={handleRegenerateImage} disabled={isUpdating} className="flex flex-col items-center justify-center gap-2 p-4 bg-slate-950 border border-slate-800 rounded-2xl hover:border-blue-500/50 hover:bg-slate-900 transition-all">
                              <RefreshCw className={`w-5 h-5 text-indigo-400 ${isUpdating ? 'animate-spin' : ''}`}/>
                              <span className="text-[9px] font-bold text-slate-400">Regenerovat</span>
                          </button>
                          <label className="flex flex-col items-center justify-center gap-2 p-4 bg-slate-950 border border-slate-800 rounded-2xl cursor-pointer hover:border-blue-500/50 hover:bg-slate-900 transition-all">
                              <Upload className="w-5 h-5 text-sky-400"/>
                              <span className="text-[9px] font-bold text-slate-400">Vlastní nahrát</span>
                              <input type="file" onChange={handleFileUpload} className="hidden" accept="image/*"/>
                          </label>
                      </div>
                  </div>

                  {currentSlide.imageValidation && (
                      <div className={`p-4 rounded-2xl border ${currentSlide.imageValidation.isOk ? 'bg-emerald-500/5 border-emerald-500/10' : 'bg-red-500/5 border-red-500/10'}`}>
                          <h5 className={`text-[10px] font-black uppercase mb-1 ${currentSlide.imageValidation.isOk ? 'text-emerald-400' : 'text-red-400'}`}>Výsledek kontroly:</h5>
                          <p className="text-slate-400 text-xs italic">"{currentSlide.imageValidation.reason}"</p>
                      </div>
                  )}
              </div>
          </div>
      )}

      {/* Ovládání */}
      <div className="absolute top-0 left-0 w-full p-6 z-50 flex justify-between items-start pointer-events-none">
        <div className="pointer-events-auto flex gap-3">
           <button onClick={onReset} className="w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center text-slate-400 border border-white/10 shadow-xl hover:text-white transition-all"><RefreshCw className="w-5 h-5" /></button>
           <button onClick={() => setIsEditing(!isEditing)} className={`w-11 h-11 rounded-full bg-slate-900/90 backdrop-blur-md flex items-center justify-center border border-white/10 shadow-xl transition-all ${isEditing ? 'text-blue-400 border-blue-500/50' : 'text-slate-400 hover:text-white'}`}><Wand2 className="w-5 h-5" /></button>
        </div>
        <div className="pointer-events-auto flex flex-col items-end gap-3 w-1/2">
            <input type="text" value={editableTitle} onChange={(e) => setEditableTitle(e.target.value)} className="text-3xl font-black text-white text-right bg-transparent border-none focus:outline-none w-full" />
            <button onClick={() => setIsExportDialogOpen(true)} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-full font-bold text-xs uppercase tracking-widest flex items-center shadow-lg transition-all"><MonitorPlay className="w-4 h-4 mr-2" /> Odevzdat práci</button>
        </div>
      </div>

      {/* Export Dialog */}
      {isExportDialogOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/80 backdrop-blur-xl animate-fade-in">
              <div className="w-full max-w-2xl bg-slate-900 border border-white/10 rounded-[3rem] shadow-2xl overflow-hidden">
                  <div className="flex border-b border-white/5">
                      <button onClick={() => setExportTab('files')} className={`flex-1 py-6 font-black text-sm tracking-widest uppercase transition-all ${exportTab === 'files' ? 'text-blue-400 border-b-2 border-blue-500 bg-blue-500/5' : 'text-slate-500'}`}>Soubory ke stažení</button>
                      <button onClick={() => setExportTab('guide')} className={`flex-1 py-6 font-black text-sm tracking-widest uppercase transition-all ${exportTab === 'guide' ? 'text-indigo-400 border-b-2 border-indigo-500 bg-indigo-500/5' : 'text-slate-500'}`}>Jak odevzdat</button>
                      <button onClick={() => setIsExportDialogOpen(false)} className="px-6 text-slate-600 hover:text-white"><X className="w-6 h-6"/></button>
                  </div>

                  {exportTab === 'files' ? (
                      <div className="p-10 grid grid-cols-1 md:grid-cols-2 gap-4">
                          <ExportFileCard title="PowerPoint (.pptx)" desc="Učitel ho otevře přímo v Teams." icon={<Layout className="text-orange-500"/>} onClick={() => generatePPTX(data)} accent="orange"/>
                          <ExportFileCard title="Fotky Slajdů (.zip)" desc="Stažení všech slajdů jako PNG obrázků." icon={<ImageIcon className="text-emerald-500"/>} onClick={handleDownloadImages} accent="emerald"/>
                          <ExportFileCard title="PDF Dokument (.pdf)" desc="Jistota pro okamžitý náhled." icon={<Printer className="text-red-500"/>} onClick={() => window.print()} accent="red"/>
                          <ExportFileCard title="Interaktivní Web (.html)" desc="Vizuály a audio v jednom souboru." icon={<MonitorPlay className="text-blue-500"/>} onClick={() => {}} accent="blue"/>
                      </div>
                  ) : (
                      <div className="p-10 space-y-4">
                          <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-3xl p-6 flex gap-4">
                              <Info className="w-6 h-6 text-indigo-400 flex-shrink-0 mt-1" />
                              <p className="text-slate-400 text-sm leading-relaxed">Nahraj PPTX nebo PDF soubor do "Soubory" v Teams. Pro nejlepší dojem pošli učiteli i HTML soubor a napiš, ať si ho stáhne pro zobrazení animací a poslech audia.</p>
                          </div>
                      </div>
                  )}
                  <div className="p-10 pt-0 flex justify-end">
                      <button onClick={() => setIsExportDialogOpen(false)} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-2xl">Zavřít</button>
                  </div>
              </div>
          </div>
      )}

      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-6 bg-slate-900/90 backdrop-blur-2xl border border-white/10 px-8 py-4 rounded-full shadow-2xl z-50">
        <button onClick={prevSlide} disabled={currentIndex === 0} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronLeft className="w-6 h-6" /></button>
        <div className="text-white font-black text-xl w-20 text-center">{currentIndex + 1} <span className="text-slate-600">/ {totalPages}</span></div>
        <button onClick={nextSlide} disabled={currentIndex === totalPages - 1} className="p-2 text-white disabled:opacity-20 hover:scale-125 transition-all"><ChevronRight className="w-6 h-6" /></button>
      </div>
    </div>
  );
};

const ExportFileCard = ({ title, desc, icon, onClick, accent }: any) => (
    <button onClick={onClick} className="bg-slate-950 p-5 rounded-3xl border border-white/5 flex flex-col text-left group hover:border-white/10 transition-all">
        <div className="flex items-center gap-4 mb-3">
            <div className="p-2 bg-white/5 rounded-xl group-hover:scale-110 transition-transform">{icon}</div>
            <h4 className="font-bold text-white text-sm">{title}</h4>
        </div>
        <p className="text-slate-500 text-[11px] leading-relaxed">{desc}</p>
    </button>
);

import React, { useState } from 'react';
import { InputSection } from './components/InputSection';
import { LoadingScreen } from './components/LoadingScreen';
import { PresentationViewer } from './components/PresentationViewer';
import { AppState, PresentationData, Slide } from './types';
import { generatePresentationStructure, generateSlideImage, generateSlideAudio, validateImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    step: 'input',
    topic: '',
    voice: 'Kore',
    slideCount: 5,
    files: [],
    filePreviews: [],
    presentation: null,
    currentSlideIndex: 0,
    loadingStatus: '',
    progress: 0
  });

  const getRandomShape = () => {
    const shapes = ['rounded-[3rem]', 'rounded-tl-[5rem] rounded-br-[5rem]', 'rounded-tr-[5rem] rounded-bl-[5rem]', 'rounded-[4rem]'];
    return shapes[Math.floor(Math.random() * shapes.length)];
  };

  const getCoordinates = (index: number) => {
      const colWidth = 1600;
      const rowHeight = 1000;
      const cols = 3; 
      const row = Math.floor(index / cols);
      const colPos = index % cols;
      const actualCol = row % 2 === 0 ? colPos : (cols - 1) - colPos;
      return { x: actualCol * colWidth, y: row * rowHeight };
  };

  const handleGenerateStructure = async () => {
    setState(prev => ({ ...prev, step: 'generating', loadingStatus: 'Sestavuji strukturu a vyhledávám podklady...', progress: 15 }));
    try {
      const { slides, sources, title } = await generatePresentationStructure(state.topic, state.slideCount, state.files);
      const processedSlides: Slide[] = slides.map((s, index) => {
          const coords = getCoordinates(index);
          return { ...s, shape: getRandomShape(), x: coords.x, y: coords.y, layout: index % 2 === 0 ? 'classic' : 'reversed' };
      });
      setState(prev => ({ ...prev, step: 'preview', presentation: { topic: state.topic, presentationTitle: title, slides: processedSlides, sources }, progress: 100 }));
      generateContentBackground(processedSlides, state.voice);
    } catch (error) {
      alert("Chyba při generování.");
      setState(prev => ({ ...prev, step: 'input' }));
    }
  };

  const generateContentBackground = async (slides: Slide[], voice: string) => {
      for (let i = 0; i < slides.length; i++) {
          const slide = slides[i];
          generateSlideImage(slide.imagePrompt).then(async img => {
              if (img) {
                const validation = await validateImage(img, slide.title, slide.bulletPoints);
                updateSlide(i, { imageBase64: img, imageValidation: validation });
              }
          });
      }
      for (let i = 0; i < slides.length; i++) {
         try {
             setState(prev => ({ ...prev, loadingStatus: `Dabuji slide ${i + 1}...` }));
             const audio = await generateSlideAudio(slides[i].speakerNotes, voice);
             if (audio) updateSlide(i, { audioBase64: audio });
             await new Promise(r => setTimeout(r, 800));
         } catch (e) {}
      }
      setState(prev => ({ ...prev, loadingStatus: 'Hotovo.' }));
  };

  const updateSlide = (index: number, updates: Partial<Slide>) => {
      setState(cur => {
          if (!cur.presentation) return cur;
          const newSlides = [...cur.presentation.slides];
          if (newSlides[index]) newSlides[index] = { ...newSlides[index], ...updates };
          return { ...cur, presentation: { ...cur.presentation, slides: newSlides } };
      });
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white font-sans selection:bg-blue-500/30">
      {state.step === 'input' && <div className="container mx-auto px-4 py-8"><InputSection {...state} setTopic={t => setState(p => ({...p, topic: t}))} setSlideCount={c => setState(p => ({...p, slideCount: c}))} setVoice={v => setState(p => ({...p, voice: v}))} setFiles={f => setState(p => ({...p, files: f}))} onGenerate={handleGenerateStructure} onShowDemo={() => {}} isGenerating={false} /></div>}
      {state.step === 'generating' && <LoadingScreen status={state.loadingStatus} progress={state.progress} />}
      {state.step === 'preview' && state.presentation && <PresentationViewer data={state.presentation} loadingStatus={state.loadingStatus} onReset={() => setState(p => ({...p, step: 'input', presentation: null}))} onUpdateSlide={updateSlide} />}
    </div>
  );
};

export default App;
